// src/components/modules/FolderCard/useFolderCardLogic.js
import { useState, useMemo } from 'react';
import { isShortcutItem } from '../../../utils/permissionUtils';
import { buildDragPayload, writeDragPayloadToDataTransfer, readDragPayloadFromDataTransfer } from '../../../utils/dragPayloadUtils';
import { withDarkGradientVariant } from '../../../utils/subjectConstants';

export const useFolderCardLogic = ({
    folder,
    allFolders, // <--- NEW PROP: We need the list of ALL folders to look up children
    allSubjects,
    cardScale,
    canDrop,
    draggable,
    onDragOver,
    onDrop,          
    onDropFolder,    
    onDropReorder,
    onDragStart,
    onDragEnd,
    position
}) => {
    const [isOver, setIsOver] = useState(false);
    
    // --- COUNTING LOGIC: Count all descendants by querying relationships ---
    const { subjectCount, folderCount, totalCount } = useMemo(() => {
        if (!allFolders) {
            return { 
                subjectCount: 0, 
                folderCount: 0, 
                totalCount: 0 
            };
        }

        const visited = new Set();
        const getFolderParentId = (entry) => {
            if (!entry) return null;
            if (isShortcutItem(entry)) return entry.shortcutParentId ?? entry.parentId ?? null;
            return entry.parentId ?? null;
        };

        const getSubjectParentId = (entry) => {
            if (!entry) return null;
            if (isShortcutItem(entry)) return entry.shortcutParentId ?? entry.folderId ?? entry.parentId ?? null;
            return entry.folderId ?? null;
        };

        const traverse = (folderId) => {
            if (visited.has(folderId)) return { s: 0, f: 0 };
            visited.add(folderId);

            // Find this folder
            const currentFolder = allFolders.find(f => (f.shortcutId || f.id) === folderId || f.id === folderId);
            if (!currentFolder) return { s: 0, f: 0 };

            // Count direct children by querying parentId/folderId
            // Get child folders where parentId/shortcutParentId === folderId
            const childFolders = allFolders.filter(f => getFolderParentId(f) === folderId);
            const childSubjects = Array.isArray(allSubjects)
                ? allSubjects.filter(s => getSubjectParentId(s) === folderId)
                : [];
            
            let s = childSubjects.length;
            let f = childFolders.length;

            // Recursively count descendants
            childFolders.forEach(child => {
                const childStats = traverse(child.id);
                s += childStats.s;
                f += childStats.f;
            });

            return { s, f };
        };

        visited.clear();
        const stats = traverse(folder.id);

        return {
            subjectCount: stats.s,
            folderCount: stats.f,
            totalCount: stats.s + stats.f
        };

    }, [folder, allFolders, allSubjects]);

    // --- VISUAL & STYLE ---
    const isModern = folder.cardStyle === 'modern';
    const fillColor = folder.modernFillColor || folder.fillColor;
    const scaleMultiplier = cardScale / 100;
    const gradientClass = withDarkGradientVariant(folder.color || 'from-amber-400 to-amber-600');

    // --- DRAG AND DROP HANDLERS ---
    const handleDragOver = (e) => {
        console.log('[DND] FolderCard handleDragOver:', { canDrop, draggable, position });
        if (canDrop) {
            e.preventDefault();
            e.stopPropagation();
            setIsOver(true);
        } else if (draggable && onDragOver) {
            e.preventDefault();
            onDragOver(e, position);
        }
    };

    const handleDragLeave = (e) => {
        console.log('[DND] FolderCard handleDragLeave:', { position });
        e.preventDefault();
        e.stopPropagation();
        setIsOver(false);
    };

    const handleDrop = (e) => {
        const draggedData = readDragPayloadFromDataTransfer(e.dataTransfer);
        console.log('[DND] FolderCard handleDrop:', {
            folderId: folder.id,
            canDrop,
            draggable,
            position,
            subjectId: draggedData?.type === 'subject' ? draggedData.id : null,
            draggedPosition: draggedData?.position,
            droppedFolderId: draggedData?.type === 'folder' ? draggedData.id : null
        });
        e.preventDefault();
        e.stopPropagation();
        setIsOver(false);

        const subjectId = draggedData?.type === 'subject' ? draggedData.id : null;
        const subjectShortcutId = draggedData?.type === 'subject' ? (draggedData.shortcutId || null) : null;
        const subjectParentId = draggedData?.type === 'subject' ? (draggedData.parentId || null) : null;
        const draggedPosition = draggedData?.position;
        const droppedFolderId = draggedData?.type === 'folder' ? draggedData.id : null;
        const droppedFolderShortcutId = draggedData?.type === 'folder' ? (draggedData.shortcutId || null) : null;

        if (canDrop && onDrop && subjectId && !droppedFolderId) {
            const subjectType = 'subject';
            console.log('[DND] FolderCard handleDrop → onDrop:', {
                folderId: folder.id,
                subjectId,
                subjectType,
                subjectParentId,
                subjectShortcutId
            });
            onDrop(folder.id, subjectId, subjectType, subjectParentId, subjectShortcutId || null);
        }
        else if (canDrop && onDropFolder && droppedFolderId && droppedFolderId !== folder.id) {
            console.log('[DND] FolderCard handleDrop → onDropFolder:', { folderId: folder.id, droppedFolderId, droppedFolderShortcutId });
            onDropFolder(folder.id, droppedFolderId, droppedFolderShortcutId);
        }
        else if (draggable && onDropReorder && droppedFolderId && draggedPosition !== null && draggedPosition !== undefined) {
            const reorderId = droppedFolderShortcutId || droppedFolderId;
            console.log('[DND] FolderCard handleDrop → onDropReorder:', { reorderId, droppedFolderId, droppedFolderShortcutId, draggedPosition, position });
            onDropReorder(reorderId, draggedPosition, position);
        }
    };

    const handleDragStart = (e) => {
        if (draggable && onDragStart) {
            e.dataTransfer.effectAllowed = 'move';
            const dragData = buildDragPayload({
                id: folder.id,
                type: 'folder',
                parentId: folder.shortcutParentId ?? folder.parentId ?? null,
                shortcutId: folder.shortcutId || null,
                position
            });
            writeDragPayloadToDataTransfer(e.dataTransfer, dragData);
            onDragStart(folder, position);
        }
    };

    const handleDragEnd = (e) => {
        if (draggable && onDragEnd) {
            onDragEnd();
        }
    };

    return {
        state: { isOver },
        data: {
            subjectCount,
            folderCount,
            totalCount,
            isModern,
            fillColor,
            scaleMultiplier,
            gradientClass
        },
        handlers: {
            handleDragOver,
            handleDragLeave,
            handleDrop,
            handleDragStart,
            handleDragEnd
        }
    };
};

// src/components/modules/ListItems/FolderListItem.jsx
import React, { useState, useMemo, useRef, useLayoutEffect } from 'react';
import { ChevronRight, Folder, GripVertical, Users, MoreVertical, Edit2, Trash2, Share2, RotateCcw } from 'lucide-react';
import { createPortal } from 'react-dom';
import SubjectIcon from '../../ui/SubjectIcon';
import ListViewItem from '../ListViewItem';
import { useGhostDrag } from '../../../hooks/useGhostDrag';
import { shouldShowEditUI, shouldShowDeleteUI, canEdit as canEditItem, getPermissionLevel, isShortcutItem } from '../../../utils/permissionUtils';
import { buildDragPayload, writeDragPayloadToDataTransfer, readDragPayloadFromDataTransfer } from '../../../utils/dragPayloadUtils';
import { SHORTCUT_LIST_MENU_WIDTH } from '../shared/shortcutMenuConfig';
import { withDarkGradientVariant } from '../../../utils/subjectConstants';

const FolderListItem = ({ 
    user,
    item, 
    index,
    parentId,
    depth = 0,
    allFolders, 
    allSubjects, 
    onNavigate, 
    onNavigateSubject,
    onEdit,
    onDelete,
    onShare = () => {},
    onGoToFolder,
    disableAllActions = false,
    disableDeleteActions = false,
    disableUnshareActions = false,
    cardScale = 100, 
    onDragStart,
    onDragEnd,
    onDropAction,
    draggable = true,
    path,
    onFocusItem = () => {},
    getCardVisualState = () => ({ isAnimating: false, isCutPending: false })
}) => {
    const HEADER_SAFE_TOP = 112;
    const MENU_MARGIN = 8;
    const [isExpanded, setIsExpanded] = useState(false);
    const [isHovered, setIsHovered] = useState(false);
    const [isDragOver, setIsDragOver] = useState(false);
    const [showMenu, setShowMenu] = useState(false);
    const menuBtnRef = useRef(null);
    const [menuPos, setMenuPos] = useState({ top: 0, left: 0 });
    const currentUserId = user?.uid || null;
    const showEditUI = currentUserId ? shouldShowEditUI(item, currentUserId) : false;
    const showDeleteUI = currentUserId ? shouldShowDeleteUI(item, currentUserId) : false;
    const canShare = currentUserId ? canEditItem(item, currentUserId) : false;
    const isShortcut = isShortcutItem(item);
    const isHiddenFromManual = item?.hiddenInManual === true;
    const isOrphan = item?.isOrphan === true;
    const isMovedToShared = item?._reason === 'moved-to-shared-folder';
    const orphanMessage = item?._reason === 'access-revoked'
        ? 'La carpeta ya no está compartida'
        : item?._reason === 'moved-to-shared-folder'
            ? `Esta carpeta se ha movido a la carpeta ${item?._movedToFolderName || 'compartida del creador'}`
            : 'La carpeta se ha eliminado';
    const shortcutPermissionLevel = isShortcut && currentUserId ? getPermissionLevel(item, currentUserId) : 'none';
    const isShortcutEditor = shortcutPermissionLevel === 'editor' || shortcutPermissionLevel === 'owner';
    const canShareFromMenu = isShortcut ? isShortcutEditor : canShare;
    const isSourceOwner = Boolean(currentUserId && item?.ownerId && item.ownerId === currentUserId);
    const resolveFolderParentId = (folderEntry) => {
        if (!folderEntry) return null;
        if (isShortcutItem(folderEntry)) return folderEntry.shortcutParentId ?? folderEntry.parentId ?? null;
        return folderEntry.parentId ?? null;
    };
    const isInsideSharedFolder = useMemo(() => {
        if (!Array.isArray(allFolders)) return false;
        let cursorId = resolveFolderParentId(item);
        let safety = 0;
        while (cursorId && safety < 200) {
            const cursor = allFolders.find(folder => folder?.id === cursorId);
            if (!cursor) return false;
            if (cursor.isShared === true) return true;
            cursorId = resolveFolderParentId(cursor);
            safety += 1;
        }
        return false;
    }, [item, allFolders]);
    const effectiveShowEditUI = !disableAllActions && showEditUI;
    const effectiveCanShareFromMenu = !disableAllActions && canShareFromMenu;
    const effectiveShowDeleteUI = !disableAllActions && !disableDeleteActions && showDeleteUI;
    const unshareBlocked = disableUnshareActions || isInsideSharedFolder;
    const canShowShortcutDelete = !disableAllActions && !disableDeleteActions && isShortcut && (isOrphan || (!isSourceOwner && !unshareBlocked));
    const canShowShortcutVisibility = !disableAllActions && isShortcut;
    const hasMenuActions = effectiveShowEditUI || effectiveCanShareFromMenu || effectiveShowDeleteUI || canShowShortcutVisibility || canShowShortcutDelete;


    const scale = cardScale / 100;
    const type = 'folder';
    // Minimum scale for the menu is 1 (100%)
    const menuScale = Math.max(scale, 1);
    const folderGradientClass = withDarkGradientVariant(item?.color || 'from-indigo-500 to-purple-500');

