                        </div>
                    ) : (
                        <div style={{ width: `${48 * scaleMultiplier}px`, height: `${48 * scaleMultiplier}px` }}>
                            <SubjectIcon 
                                iconName={subject.icon} 
                                className="text-white opacity-80" 
                                style={{ 
                                    width: `${48 * scaleMultiplier}px`, 
                                    height: `${48 * scaleMultiplier}px` 
                                }}
                            />
                        </div>
                    )}

                    {isPassedShortcut && (
                        <span
                            className="inline-flex items-center rounded-full bg-emerald-100/90 dark:bg-emerald-500/20 text-emerald-700 dark:text-emerald-300 font-semibold border border-emerald-200 dark:border-emerald-400/20"
                            style={{
                                fontSize: `${11 * scaleMultiplier}px`,
                                padding: `${4 * scaleMultiplier}px ${10 * scaleMultiplier}px`
                            }}
                        >
                            Aprobada
                        </span>
                    )}
                </div>
                
                <div>
                    {subject.course && (
                        <p 
                            className={`font-medium tracking-wide ${
                                isModern 
                                    ? (isPassedShortcut ? 'text-emerald-700 dark:text-emerald-300' : 'text-gray-500 dark:text-gray-400') 
                                    : 'text-white opacity-90'
                            }`}
                            style={{ fontSize: `${14 * scaleMultiplier}px` }}
                        >
                            {subject.course}
                        </p>
                    )}
                    
                    <div className="flex items-center gap-2 mb-2">
                        {/* 1. Subject Name */}
                        <h3 
                            className={`font-bold tracking-tight truncate ${
                                isModern 
                                    ? `bg-gradient-to-br ${isPassedShortcut ? 'from-emerald-500 via-cyan-500 to-teal-600 dark:from-emerald-300 dark:via-cyan-300 dark:to-teal-400' : subjectGradientClass} bg-clip-text text-transparent` 
                                    : 'text-white'
                            }`}
                            style={{ fontSize: `${24 * scaleMultiplier}px` }}
                        >
                            {subject.name}
                        </h3>

                        {/* 2. Shared Icon (at the right) */}
                        {!hideSharedIndicator && (
                            subject.isShared === true ||
                            (Array.isArray(subject.sharedWith) && subject.sharedWith.length > 0) ||
                            (Array.isArray(subject.sharedWithUids) && subject.sharedWithUids.length > 0)
                        ) && (
                            <div 
                                className={`flex items-center justify-center rounded-full ${
                                    isModern ? '' : 'bg-white/20'
                                }`}
                                style={{ 
                                    width: `${24 * scaleMultiplier}px`, 
                                    height: `${24 * scaleMultiplier}px`,
                                    minWidth: `${24 * scaleMultiplier}px`
                                }}
                                title="Asignatura compartida"
                            >
                                <Users 
                                    className={isModern ? `${getIconColor(subject.color)} drop-shadow` : "text-white"}
                                    style={{ width: `${14 * scaleMultiplier}px`, height: `${14 * scaleMultiplier}px` }}
                                />
                            </div>
                        )}
                    </div>

                    {isPassedShortcut && (
                        <p
                            className="mt-2 text-emerald-700 dark:text-emerald-300 font-medium"
                            style={{ fontSize: `${12 * scaleMultiplier}px` }}
                        >
                            Disponible en cursos y uso reciente.
                        </p>
                    )}

                    {subject.tags && subject.tags.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-1">
                            {subject.tags.slice(0, 3).map(tag => (
                                <span 
                                    key={tag}
                                    className={`rounded ${
                                        isModern 
                                            ? 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400' 
                                            : 'bg-white/20 text-white/90'
                                    }`}
                                    style={{ 
                                        fontSize: `${10 * scaleMultiplier}px`,
                                        padding: `${2 * scaleMultiplier}px ${6 * scaleMultiplier}px`
                                    }}
                                >
                                    #{tag}
                                </span>
                            ))}
                            {subject.tags.length > 3 && (
                                <span 
                                    className={
                                        isModern 
                                            ? 'text-gray-400 dark:text-gray-500' 
                                            : 'text-white/80'
                                    }
                                    style={{ fontSize: `${10 * scaleMultiplier}px` }}
                                >
                                    +{subject.tags.length - 3}
                                </span>
                            )}
                        </div>
                    )}
                    
                </div>
            </div>

            {isOrphan && (
                <>
                    <div className="absolute bottom-4 left-4 right-4 z-20 pointer-events-none text-center">
                        <span
                            className={`font-semibold ${isModern ? 'text-slate-700 dark:text-slate-200' : 'text-white/95'}`}
                            style={{ fontSize: `${12 * scaleMultiplier}px` }}
                        >
                            {orphanMessage}
                        </span>
                    </div>
                    <div className="absolute inset-0 z-40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                        {isMovedToShared && subject?._movedToFolderId ? (
                            <div className="pointer-events-auto flex items-center gap-2">
                                <button
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        if (typeof onGoToFolder === 'function') {
                                            onGoToFolder(subject._movedToFolderId);
                                        }
                                    }}
                                    className="px-4 py-2 rounded-lg font-semibold shadow-lg flex justify-center items-center"
                                    style={{
                                        fontSize: `${13 * scaleMultiplier}px`,
                                        background: 'rgba(30,41,59,0.35)',
                                        border: '1px solid #1e293b',
                                        color: '#fff',
                                        transition: 'background 0.2s',
                                    }}
                                >
                                    {`Ir a carpeta ${subject?._movedToFolderName || ''}`.trim()}
                                </button>
                                <button
                                    onClick={(e) => onDelete(e, subject, 'deleteShortcut')}
                                    className="px-4 py-2 rounded-lg bg-red-600 hover:bg-red-700 text-white font-semibold shadow-lg"
                                    style={{ fontSize: `${13 * scaleMultiplier}px` }}
                                >
                                    Eliminar
                                </button>
                            </div>
                        ) : (
                            <button
                                onClick={(e) => onDelete(e, subject, 'deleteShortcut')}
                                className="pointer-events-auto px-4 py-2 rounded-lg bg-red-600 hover:bg-red-700 text-white font-semibold shadow-lg"
                                style={{ fontSize: `${13 * scaleMultiplier}px` }}
                            >
                                Eliminar
                            </button>
                        )}
                    </div>
                </>
            )}
        </div>
    );
};

