// src/pages/Content/StudyGuideEditor.jsx
import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
    ChevronLeft, Plus, Trash2, Save, Eye,
    ChevronDown, ChevronUp, BookOpen, Calculator, AlertCircle,
    CheckCircle2, Loader2, PenLine, X, Copy, MoveUp, MoveDown,
    LayoutList, Sparkles, ShieldAlert
} from 'lucide-react';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from '../../firebase/config';
import { canEdit } from '../../utils/permissionUtils';

import 'katex/dist/katex.min.css';
import { BlockMath } from 'react-katex';

// ==================== CONSTANTS ====================
const EMPTY_SECTION = () => ({
    title: '',
    content: '',
    formulas: []
});

const TOAST_DURATION = 3500;

// ==================== SUBCOMPONENTS ====================

const Toast = ({ message, type, onClose }) => {
    useEffect(() => {
        const t = setTimeout(onClose, TOAST_DURATION);
        return () => clearTimeout(t);
    }, [onClose]);

    return (
        <div className={`fixed bottom-8 right-8 z-[100] flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border-2 font-bold text-sm transition-all duration-500 animate-in slide-in-from-bottom-4 fade-in ${
            type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800 dark:bg-emerald-950 dark:border-emerald-800 dark:text-emerald-200' :
            type === 'error' ? 'bg-red-50 border-red-200 text-red-800 dark:bg-red-950 dark:border-red-800 dark:text-red-200' :
            'bg-blue-50 border-blue-200 text-blue-800 dark:bg-blue-950 dark:border-blue-800 dark:text-blue-200'
        }`}>
            {type === 'success' && <CheckCircle2 className="w-5 h-5 text-emerald-600 shrink-0" />}
            {type === 'error' && <AlertCircle className="w-5 h-5 text-red-600 shrink-0" />}
            {type === 'loading' && <Loader2 className="w-5 h-5 text-blue-600 shrink-0 animate-spin" />}
            <span>{message}</span>
            <button onClick={onClose} className="ml-2 opacity-60 hover:opacity-100 transition-opacity">
                <X className="w-4 h-4" />
            </button>
        </div>
    );
};

const FormulaEditor = ({ formula, index, onUpdate, onDelete, topicGradient, baseColor }) => {
    return (
        <div className="group/formula relative bg-white dark:bg-slate-900 rounded-2xl border-2 border-slate-100 dark:border-slate-700 hover:border-slate-200 dark:hover:border-slate-600 shadow-sm transition-all duration-300 overflow-hidden">
            <div className={`h-1 w-full bg-gradient-to-r ${topicGradient}`} />
            <div className="p-4 space-y-3">
                <div className="flex items-center justify-between">
                    <span className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Fórmula #{index + 1}</span>
                    <button onClick={onDelete} className="p-1.5 rounded-lg text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-950 transition-all">
                        <Trash2 className="w-3.5 h-3.5" />
                    </button>
                </div>
                <textarea
                    value={formula}
                    onChange={(e) => onUpdate(e.target.value)}
                    placeholder="Ej: F = m \cdot a"
                    rows={2}
                    className={`w-full px-3 py-2.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-mono text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-${baseColor}-300 focus:border-transparent resize-none transition-all`}
                />
                <div className="py-2 px-3 bg-slate-50 dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 text-center overflow-x-auto">
                    <BlockMath math={formula || '\\text{Escribe LaTeX arriba}'} />
                </div>
            </div>
        </div>
    );
};

const SectionEditor = ({ section, index, total, topicGradient, baseColor, onUpdate, onDelete, onMoveUp, onMoveDown, onDuplicate }) => {
    const [isExpanded, setIsExpanded] = useState(true);
    const updateField = (field, value) => onUpdate({ ...section, [field]: value });
    const addFormula = () => onUpdate({ ...section, formulas: [...(section.formulas || []), ''] });
    const updateFormula = (fIdx, value) => {
        const newFormulas = [...(section.formulas || [])];
        newFormulas[fIdx] = value;
        onUpdate({ ...section, formulas: newFormulas });
    };
    const deleteFormula = (fIdx) => {
        const newFormulas = (section.formulas || []).filter((_, i) => i !== fIdx);
        onUpdate({ ...section, formulas: newFormulas });
    };

    return (
        <div className="relative group/section">
            <div className={`absolute inset-0 bg-gradient-to-br ${topicGradient} rounded-[2.5rem] blur-2xl opacity-0 group-hover/section:opacity-10 transition-opacity duration-500`} />
            <div className="relative bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-xl border-2 border-slate-100 dark:border-slate-700 overflow-hidden">
                <div className={`h-1.5 w-full bg-gradient-to-r ${topicGradient}`} />
                <div className="px-6 py-4 flex items-center gap-4">
                    <div className={`relative w-10 h-10 rounded-xl bg-gradient-to-br ${topicGradient} flex items-center justify-center text-white font-black shadow-lg ring-2 ring-white dark:ring-slate-800 shrink-0`}>
                        {index + 1}
                    </div>
                    <input
                        type="text"
                        value={section.title}
                        onChange={(e) => updateField('title', e.target.value)}
                        placeholder="Título del capítulo..."
                        className="flex-1 text-lg font-black text-slate-900 dark:text-slate-100 bg-transparent border-none outline-none placeholder-slate-300 dark:placeholder-slate-600"
                    />
                    <div className="flex items-center gap-1">
                        <button onClick={onMoveUp} disabled={index === 0} className="p-1.5 text-slate-400 hover:text-slate-700 dark:hover:text-slate-300 disabled:opacity-20"><MoveUp className="w-4 h-4" /></button>
                        <button onClick={onMoveDown} disabled={index === total - 1} className="p-1.5 text-slate-400 hover:text-slate-700 dark:hover:text-slate-300 disabled:opacity-20"><MoveDown className="w-4 h-4" /></button>
                        <button onClick={onDuplicate} className={`p-1.5 text-slate-400 hover:text-${baseColor}-600`}><Copy className="w-4 h-4" /></button>
                        <button onClick={onDelete} className="p-1.5 text-slate-400 hover:text-red-500"><Trash2 className="w-4 h-4" /></button>
                        <button onClick={() => setIsExpanded(!isExpanded)} className="p-1.5 text-slate-400">
                            <ChevronDown className={`w-4 h-4 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                        </button>
                    </div>
                </div>

                {isExpanded && (
                    <div className="px-6 pb-6 space-y-5 border-t border-slate-50 dark:border-slate-800 pt-5">
                        <textarea
                            value={section.content}
                            onChange={(e) => updateField('content', e.target.value)}
                            placeholder="Escribe el contenido..."
                            rows={6}
                            className={`w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm text-slate-900 dark:text-slate-100 focus:outline-none focus:ring-2 focus:ring-${baseColor}-300 resize-y transition-all font-mono leading-relaxed`}
                        />
                        <div className="space-y-3">
                            <div className="flex items-center justify-between">
                                <label className="text-xs font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest flex items-center gap-2">
                                    <Calculator className="w-3.5 h-3.5" /> Fórmulas ({section.formulas?.length || 0})
                                </label>
                                <button onClick={addFormula} className={`flex items-center gap-1.5 px-3 py-1.5 bg-gradient-to-r ${topicGradient} text-white rounded-lg text-xs font-black shadow-md hover:-translate-y-0.5 transition-all`}>
                                    <Plus className="w-3 h-3" /> Añadir fórmula
                                </button>
                            </div>
                            <div className="space-y-3">
                                {(section.formulas || []).map((f, fi) => (
                                    <FormulaEditor key={fi} formula={f} index={fi} topicGradient={topicGradient} baseColor={baseColor} onUpdate={(v) => updateFormula(fi, v)} onDelete={() => deleteFormula(fi)} />
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

// ==================== MAIN COMPONENT ====================

const StudyGuideEditor = ({ user }) => {
    const { subjectId, topicId, guideId, fileId } = useParams();
    const activeDocId = fileId || guideId;
    const navigate = useNavigate();

    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [hasEditPermission, setHasEditPermission] = useState(false);
    const [topicGradient, setTopicGradient] = useState('from-indigo-500 to-purple-600');
    const [toast, setToast] = useState(null);

    const [title, setTitle] = useState('');
    const [subtitle, setSubtitle] = useState('');
    const [sections, setSections] = useState([]);

    const baseColor = useMemo(() => {
        const firstPart = topicGradient.split(' ')[0] || '';
        return firstPart.replace('from-', '').split('-')[0] || 'indigo';
    }, [topicGradient]);

    // ✅ NAVEGACIÓN DIRECTA CORREGIDA: Te lleva a la StudyGuide
    const goToView = () => {
        if (subjectId && topicId && activeDocId) {
            navigate(`/home/subject/${subjectId}/topic/${topicId}/resumen/${activeDocId}`);
        } else {
            navigate(-1);
        }
    };

    const showToast = useCallback((message, type = 'success') => setToast({ message, type }), []);

    useEffect(() => {
        const load = async () => {
            if (!activeDocId) return;
            try {
                // 1. Check permissions first
                const topicSnap = await getDoc(doc(db, 'topics', topicId));
                if (!topicSnap.exists()) {
                    showToast('Tema no encontrado', 'error');
                    navigate(-1);
                    return;
                }
                
                const topicData = { id: topicSnap.id, ...topicSnap.data() };
                const hasPermission = canEdit(topicData, user?.uid);
                setHasEditPermission(hasPermission);
                
                if (!hasPermission) {
                    setLoading(false);
                    return;
                }
                
                // 2. Load subject color (Priority)
                const subjectSnap = await getDoc(doc(db, 'subjects', subjectId));
                if (subjectSnap.exists() && subjectSnap.data().color) {
                    setTopicGradient(subjectSnap.data().color);
                }

                // 3. Load study guide
                const guideSnap = await getDoc(doc(db, 'resumen', activeDocId));
                if (guideSnap.exists()) {
                    const raw = guideSnap.data();
                    setTitle(raw.title || '');
                    setSubtitle(raw.subtitle || '');
                    const content = typeof raw.studyGuide === 'string' ? JSON.parse(raw.studyGuide) : (raw.studyGuide || []);
                    setSections(content);
                }
            } catch (err) {
                showToast('Error al cargar datos', 'error');
            } finally {
                setLoading(false);
            }
        };
        load();
    }, [subjectId, topicId, activeDocId, showToast, navigate, user]);

    const handleSave = async () => {
        setSaving(true);
        showToast('Guardando cambios...', 'loading');
        try {
            await setDoc(doc(db, 'resumen', activeDocId), {
                title,
                subtitle,
                studyGuide: JSON.stringify(sections),
                updatedAt: new Date().toISOString()
            }, { merge: true });
            showToast('¡Cambios guardados!', 'success');
        } catch (err) {
            showToast('Error al guardar', 'error');
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="min-h-screen flex flex-col items-center justify-center gap-4 bg-slate-50 dark:bg-slate-950 font-bold text-slate-400 dark:text-slate-500"><Loader2 className="w-10 h-10 animate-spin" /> Cargando editor...</div>;

    // *** PERMISSION DENIED UI ***
    if (!hasEditPermission) {
        return (
            <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 px-6">
                <div className="max-w-md w-full bg-white dark:bg-slate-900 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-700 p-12 text-center">
                    <div className="w-20 h-20 bg-amber-100 dark:bg-amber-900/30 rounded-full flex items-center justify-center mx-auto mb-6">
                        <ShieldAlert className="w-10 h-10 text-amber-600 dark:text-amber-400" />
                    </div>
                    <h1 className="text-3xl font-black text-slate-800 dark:text-slate-100 mb-3">Sin permisos de edición</h1>
                    <p className="text-slate-500 dark:text-slate-400 mb-8 leading-relaxed">
                        No tienes permisos para editar esta guía de estudio. Solo el creador o colaboradores con acceso de edición pueden modificar el contenido.
                    </p>
                    <div className="flex flex-col gap-3">
                        <button
                            onClick={() => navigate(-1)}
                            className="w-full flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all"
                        >
                            <ChevronLeft className="w-5 h-5" /> Volver
                        </button>
                        <button
                            onClick={goToView}
                            className="w-full flex items-center justify-center gap-2 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 px-6 py-3 rounded-xl font-bold hover:bg-slate-200 dark:hover:bg-slate-700 transition-all"
                        >
                            <Eye className="w-5 h-5" /> Ver en modo lectura
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className={`min-h-screen bg-slate-50 dark:bg-slate-950 pb-32`}>
            {/* HEADER */}
            <div className="sticky top-0 z-40 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md border-b-2 border-white/60 dark:border-slate-700/60 shadow-xl p-4">
                <div className="max-w-5xl mx-auto flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-xl text-slate-600 dark:text-slate-400 transition-colors"><ChevronLeft /></button>
                        <div>
                            <div className="flex items-center gap-2">
                                <PenLine className={`w-4 h-4 text-${baseColor}-500`} />
                                <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Modo Editor</span>
                            </div>
                            <h1 className="font-black text-slate-900 dark:text-slate-100 truncate max-w-[200px] sm:max-w-md">{title || 'Sin título'}</h1>
                        </div>
                    </div>
                    <div className="flex gap-2">
                        {/* BOTÓN VER GUÍA */}
                        <button onClick={goToView} className="px-4 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-700 dark:text-slate-300 rounded-xl font-bold text-sm flex items-center gap-2 transition-all shadow-sm">
                            <Eye className="w-4 h-4" /> <span>Ver guía</span>
                        </button>
                        <button onClick={handleSave} disabled={saving} className={`px-5 py-2 bg-gradient-to-r ${topicGradient} text-white rounded-xl font-black text-sm shadow-lg flex items-center gap-2 transition-all hover:scale-105 active:scale-95 disabled:opacity-50`}>
                            {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />} <span>Guardar</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* CONTENT */}
            <div className="max-w-5xl mx-auto px-6 py-10 space-y-10">
                {/* META FIELDS */}
                <div className="bg-white dark:bg-slate-900 rounded-[2.5rem] shadow-xl border-2 border-slate-100 dark:border-slate-700 p-8 space-y-6 relative overflow-hidden">
                    <div className={`h-1.5 w-full bg-gradient-to-r ${topicGradient} absolute top-0 left-0`} />
                    <div className="space-y-2">
                        <label className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Título de la guía</label>
                        <input type="text" value={title} onChange={(e) => setTitle(e.target.value)} className={`w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-xl font-black text-slate-900 dark:text-slate-100 focus:ring-2 focus:ring-${baseColor}-300 focus:bg-white dark:focus:bg-slate-700 outline-none transition-all`} />
                    </div>
                    <div className="space-y-2">
                        <label className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest ml-1">Subtítulo</label>
                        <input type="text" value={subtitle} onChange={(e) => setSubtitle(e.target.value)} className={`w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-900 dark:text-slate-100 focus:ring-2 focus:ring-${baseColor}-300 focus:bg-white dark:focus:bg-slate-700 outline-none transition-all`} />
                    </div>
                </div>

                {/* SECTIONS */}
                <div className="space-y-6">
                    <div className="flex items-center justify-between px-2">
                        <h2 className="text-xl font-black text-slate-900 dark:text-slate-100 flex items-center gap-3"><LayoutList className="text-slate-400 dark:text-slate-500" /> Capítulos ({sections.length})</h2>
                        <button onClick={() => setSections([...sections, EMPTY_SECTION()])} className={`px-4 py-2 bg-gradient-to-r ${topicGradient} text-white rounded-2xl font-black text-sm shadow-md hover:-translate-y-0.5 transition-all`}>+ Nuevo capítulo</button>
                    </div>
                    <div className="space-y-5">
                        {sections.map((s, i) => (
                            <SectionEditor key={i} section={s} index={i} total={sections.length} topicGradient={topicGradient} baseColor={baseColor}
                                onUpdate={(upd) => setSections(sections.map((sec, idx) => idx === i ? upd : sec))}
                                onDelete={() => setSections(sections.filter((_, idx) => idx !== i))}
                                onMoveUp={() => { if(i > 0) { const a = [...sections]; [a[i], a[i-1]] = [a[i-1], a[i]]; setSections(a); }}}
                                onMoveDown={() => { if(i < sections.length - 1) { const a = [...sections]; [a[i], a[i+1]] = [a[i+1], a[i]]; setSections(a); }}}
                                onDuplicate={() => { const a = [...sections]; a.splice(i + 1, 0, { ...JSON.parse(JSON.stringify(s)), title: s.title + ' (copia)' }); setSections(a); }}
                            />
                        ))}
                    </div>
                </div>

                {/* FINAL SAVE */}
                <div className="flex flex-col items-center gap-4 pt-10">
                    <button onClick={handleSave} disabled={saving} className={`px-10 py-4 bg-gradient-to-r ${topicGradient} text-white rounded-[2rem] font-black text-lg shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3 disabled:opacity-50`}>
                        {saving ? <Loader2 className="animate-spin" /> : <Save />} Guardar Cambios Finales
                    </button>
                    {/* ✅ ENLACE SECUNDARIO VER GUÍA */}
                    <button onClick={goToView} className="text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 font-bold text-sm transition-colors flex items-center gap-2">
                        <Eye className="w-4 h-4" /> Ver cómo está quedando
                    </button>
                </div>
            </div>

            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
        </div>
    );
};

export default StudyGuideEditor;

// src/pages/InstitutionAdminDashboard/InstitutionAdminDashboard.jsx
//
// ─── Refactor summary ─────────────────────────────────────────────────────────
//  • All user/invite/policy logic → hooks/useUsers.js
//  • All customization logic     → hooks/useCustomization.js
//  • Icon + Logo section         → components/customization/BrandingSection.jsx
//  • Full customization tab      → components/CustomizationTab.jsx
//  • InstitutionCustomizationView updated to accept `previewPaletteApply` prop

import React, { useEffect, useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { LayoutGrid, Palette, UserPlus, Users } from 'lucide-react';

import Header from '../../components/layout/Header';
import SudoModal from '../../components/modals/SudoModal';
import ClassesCoursesSection from './components/ClassesCoursesSection';
import UsersTabContent from './components/UsersTabContent';
import AddTeacherModal from './components/AddTeacherModal';
import CustomizationTab from './components/CustomizationTab';

import { useIdleTimeout } from '../../hooks/useIdleTimeout';
import { hasRequiredRoleAccess } from '../../utils/permissionUtils';
import { useUsers } from './hooks/useUsers';
import { useCustomization } from './hooks/useCustomization';
import { usePersistentState } from '../../hooks/usePersistentState';
import { buildInstitutionScopedPersistenceKey } from '../../utils/pagePersistence';

const TABS = [
  { key: 'users',         label: 'Usuarios',         icon: Users },
  { key: 'organization',  label: 'Cursos y Clases',   icon: LayoutGrid },
  { key: 'customization', label: 'Personalización',   icon: Palette },
];

const InstitutionAdminDashboard = ({ user }) => {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  useIdleTimeout(15);

  const institutionIdFromQuery = searchParams.get('institutionId');
  const effectiveInstitutionId = user?.role === 'admin' && institutionIdFromQuery
    ? institutionIdFromQuery
    : user?.institutionId || null;
  const activeTabKey = buildInstitutionScopedPersistenceKey('institution-admin-dashboard', effectiveInstitutionId, 'active-tab');

  const [activeTab, setActiveTab] = usePersistentState(activeTabKey, 'users');

  // ── Guard ──
  useEffect(() => {
    if (user && !hasRequiredRoleAccess(user, 'institutionadmin')) {
      console.warn('Unauthorized access attempt to Institution Admin Dashboard');
      navigate('/home');
    }
  }, [user, navigate]);

  // ── Domain logic hooks ──
  const users = useUsers(user, effectiveInstitutionId);
  const customization = useCustomization(user, effectiveInstitutionId);

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 font-sans transition-colors">
      <Header user={user} />

      <main className="pt-24 pb-12 px-6 max-w-7xl mx-auto">
        {/* Page header */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h1 className="text-3xl font-black text-slate-900 dark:text-white">Panel de Administración</h1>
            <p className="text-slate-500 dark:text-slate-400 mt-1">
              {user?.institutionId ? `Institución ID: ${user.institutionId}` : 'Configuración de Institución'}
              {effectiveInstitutionId ? `Institución ID: ${effectiveInstitutionId}` : 'Configuración de Institución'}
            </p>
          </div>
          {activeTab === 'users' && users.userType === 'teachers' && (
            <button
              onClick={() => {
                users.setShowAddUserModal(true);
              }}
              className="bg-[var(--color-primary-600)] hover:bg-[var(--color-primary-700)] text-white px-4 py-2.5 rounded-xl font-medium flex items-center gap-2 shadow-lg shadow-[var(--color-primary-200)] dark:shadow-[var(--color-primary-900)/0.2] transition-all active:scale-95"
            >
              <UserPlus className="w-5 h-5" /> Autorizar Profesor
            </button>
          )}
        </div>

        {/* Tab nav */}
        <div className="flex items-center gap-2 mb-8 border-b border-slate-200 dark:border-slate-800 overflow-x-auto whitespace-nowrap pb-px no-scrollbar">
            {TABS.map(({ key, label, icon: Icon }) => (
              <button
                key={key}
                onClick={() => setActiveTab(key)}
                className={`px-4 py-2 font-medium text-sm flex items-center gap-2 border-b-2 -mb-[2px] transition-colors ${
                activeTab === key
                  ? 'border-indigo-600 text-indigo-600 dark:text-indigo-400'
                  : 'border-transparent text-slate-500 hover:text-slate-700 dark:text-slate-400'
              }`}
            >
              <Icon className="w-4 h-4" /> {label}
            </button>
          ))}
        </div>

        {/* ── Users tab ── */}
        {activeTab === 'users' && (
          <UsersTabContent
            userType={users.userType}
            setUserType={users.setUserType}
            institutionId={effectiveInstitutionId}
            accessPolicies={users.accessPolicies}
            onSavePolicies={users.handleSavePolicies}
            isUpdatingPolicies={users.isUpdatingPolicies}
            policyMessage={users.policyMessage}
            searchTerm={users.searchTerm}
            setSearchTerm={users.setSearchTerm}
            loading={users.loading}
            teachers={users.teachers}
            students={users.students}
            allowedTeachers={users.allowedTeachers}
            onNavigateTeacher={(id) => navigate(`/institution-admin-dashboard/teacher/${id}`)}
            onNavigateStudent={(id) => navigate(`/institution-admin-dashboard/student/${id}`)}
            onRemoveAccess={users.handleRemoveAccess}
            institutionalCode={users.institutionalCode}
            onUpdateInstitutionalCode={users.handleUpdateInstitutionalCode}
            isUpdatingCode={users.isUpdatingCode}
            codeUpdateSuccess={users.codeUpdateSuccess}
            codeUpdateError={users.codeUpdateError}
            liveAccessCode={users.liveAccessCode}
            liveCodeLoading={users.liveCodeLoading}
            liveCodeError={users.liveCodeError}
          />
        )}

        {/* ── Organization tab ── */}
        {activeTab === 'organization' && (
          <ClassesCoursesSection
            user={user}
            institutionId={effectiveInstitutionId}
            allStudents={users.allStudents}
            allTeachers={users.allTeachers}
          />
        )}

        {/* ── Customization tab ── */}
        {activeTab === 'customization' && (
          <CustomizationTab
            customizationLoading={customization.customizationLoading}
            customizationSaving={customization.customizationSaving}
            customizationError={customization.customizationError}
            customizationSuccess={customization.customizationSuccess}
            customizationForm={customization.customizationForm}
            institutionName={customization.institutionName}
            iconUploading={customization.iconUploading}
            iconUploadError={customization.iconUploadError}
            customizationInitialValues={customization.customizationInitialValues}
            onIconUpload={customization.handleIconUpload}
            onLogoUpload={customization.handleLogoUpload}
            onLogoUrlSave={customization.handleLogoUrlSave}
            onSaveCustomization={customization.handleSaveCustomization}
          />
        )}
      </main>

      {/* ── Add teacher modal ── */}
      {users.showAddUserModal && (
        <AddTeacherModal
          isSubmitting={users.isSubmitting}
          newUserEmail={users.newUserEmail}
          onEmailChange={users.setNewUserEmail}
          onClose={() => users.setShowAddUserModal(false)}
          onSubmit={users.handleAddUser}
          addError={users.addError}
          addSuccess={users.addSuccess}
        />
      )}

      {/* ── Sudo confirmation modal ── */}
      <SudoModal
        isOpen={users.showSudoModal}
        onClose={() => users.setShowSudoModal(false)}
        onConfirm={users.handleConfirmSavePolicies}
        actionName="guardar las políticas de acceso"
      />
    </div>
  );
};

export default InstitutionAdminDashboard;

import React, { useState } from 'react';
import {
  BookOpen,
  CheckCircle2,
  ChevronRight,
  GraduationCap,
  Loader2,
  Search,
  Trash2,
  UserPlus,
  Copy,
  ShieldAlert,
  XCircle
} from 'lucide-react';
import { DEFAULT_ACCESS_POLICIES } from '../../../utils/institutionPolicyUtils';

const UsersTabContent = ({
  userType,
  setUserType,
  accessPolicies,
  onSavePolicies,
  isUpdatingPolicies,
  policyMessage,
  searchTerm,
  setSearchTerm,
  loading,
  teachers,
  students,
  allowedTeachers,
  onNavigateTeacher,
  onNavigateStudent,
  onRemoveAccess,
  liveAccessCode,
  liveCodeLoading,
  liveCodeError
}) => {
  // 1. Filter out the general code so it doesn't appear in the specific invites table
  const specificInvites = allowedTeachers.filter(t => t.type !== 'institutional');

  const [copied, setCopied] = useState(false);
  const [accessDeleteConfirm, setAccessDeleteConfirm] = useState({
    isOpen: false,
    inviteId: null,
    inviteLabel: ''
  });
  const [isRemovingAccess, setIsRemovingAccess] = useState(false);

  // 1. Safe policy handling and local state
  const defaultPolicy = userType === 'teachers'
    ? DEFAULT_ACCESS_POLICIES.teachers
    : DEFAULT_ACCESS_POLICIES.students;
  const currentPolicy = accessPolicies?.[userType] || defaultPolicy;
  
  const [editPolicy, setEditPolicy] = React.useState(currentPolicy);

  // 2. Update local form when admin switches between Teachers <-> Students
  React.useEffect(() => {
    if (accessPolicies) {
      setEditPolicy(accessPolicies[userType] || defaultPolicy);
    }
  }, [userType, accessPolicies]);

  // 3. Generate the LIVE code based on the current tab
  const liveCode = editPolicy.requireCode
    ? (liveAccessCode || '------')
    : 'DESACTIVADO';

  const handleCopyLiveCode = () => {
    if (liveCode === 'DESACTIVADO') return;
    navigator.clipboard.writeText(liveCode);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const requestRemoveAccess = (invite) => {
    if (!invite?.id || isRemovingAccess) return;

    setAccessDeleteConfirm({
      isOpen: true,
      inviteId: invite.id,
      inviteLabel: invite.email || invite.id
    });
  };

  const closeAccessDeleteConfirm = () => {
    if (isRemovingAccess) return;

    setAccessDeleteConfirm({
      isOpen: false,
      inviteId: null,
      inviteLabel: ''
    });
  };

  const confirmRemoveAccess = async () => {
    if (!accessDeleteConfirm.inviteId || isRemovingAccess) return;

    setIsRemovingAccess(true);
    try {
      await onRemoveAccess(accessDeleteConfirm.inviteId);
    } finally {
      setIsRemovingAccess(false);
      setAccessDeleteConfirm({
        isOpen: false,
        inviteId: null,
        inviteLabel: ''
      });
    }
  };

  return (
    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 mb-6 flex flex-col md:flex-row gap-4 justify-between">
        <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl w-fit">
          <button
            onClick={() => {
              setUserType('teachers');
              setSearchTerm('');
            }}
            className={`px-4 py-1.5 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${
              userType === 'teachers' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700'
            }`}
          >
            <BookOpen className="w-4 h-4" /> Profesores
          </button>
          <button
            onClick={() => {
              setUserType('students');
              setSearchTerm('');
            }}
            className={`px-4 py-1.5 rounded-lg text-sm font-medium flex items-center gap-2 transition-all ${
              userType === 'students' ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 dark:text-slate-400 hover:text-slate-700'
            }`}
          >
            <GraduationCap className="w-4 h-4" /> Alumnos
          </button>
        </div>
        <div className="relative flex-1 md:max-w-xs">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input
            type="text"
            placeholder="Buscar por email..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="w-full pl-9 pr-4 py-2 bg-slate-50 dark:bg-slate-800 border-none rounded-xl text-sm outline-none focus:ring-2 focus:ring-indigo-500"
          />
        </div>
      </div>

      {loading ? (
        <div className="flex justify-center py-16"><Loader2 className="w-7 h-7 animate-spin text-indigo-500" /></div>
      ) : (
        <div className="space-y-6">
          {/* SECURITY PANEL (Now outside the teacher check, so it shows for students too) */}
          {accessPolicies && (
            <div className="bg-gradient-to-br from-indigo-50 to-white dark:from-indigo-900/10 dark:to-slate-900 p-6 rounded-2xl shadow-sm border border-indigo-100 dark:border-indigo-500/20 mb-6">
              <div className="flex flex-col md:flex-row justify-between items-start gap-6 mb-6">
                <div>
                  <h3 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2 mb-1">
                    <ShieldAlert className="w-5 h-5 text-indigo-500" />
                    Seguridad de Acceso ({userType === 'teachers' ? 'Profesores' : 'Alumnos'})
                  </h3>
                  <p className="text-sm text-slate-500 dark:text-slate-400 max-w-2xl">
                    Configura cómo pueden registrarse los {userType === 'teachers' ? 'profesores' : 'alumnos'} en tu institución.
                  </p>
                </div>
                
                {/* LIVE CODE WITH COPY BUTTON */}
                <div className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-slate-200 dark:border-slate-700 text-center min-w-[150px] flex flex-col items-center">
                  <p className="text-xs text-slate-500 font-semibold uppercase mb-1">Código Actual</p>
                  <div className="flex items-center gap-2">
                    <p className="font-mono text-xl font-bold tracking-widest text-indigo-600 dark:text-indigo-400">
                      {liveCodeLoading ? '......' : liveCode}
                    </p>
                    {liveCode !== 'DESACTIVADO' && (
                      <button 
                        onClick={handleCopyLiveCode}
                        className="p-1.5 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-md transition-colors"
                        title="Copiar código"
                      >
                        {copied ? <CheckCircle2 className="w-4 h-4 text-emerald-500" /> : <Copy className="w-4 h-4 text-slate-400" />}
                      </button>
                    )}
                  </div>
                  {liveCodeError && (
                    <p className="mt-2 text-[11px] text-red-500 font-medium">{liveCodeError}</p>
                  )}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* DOMAIN SETTINGS */}
                <div className="space-y-3 p-4 bg-white/50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-700/50">
                  <label className="flex items-center gap-2 font-medium text-slate-700 dark:text-slate-300">
                    <input 
                      type="checkbox" 
                      checked={editPolicy.requireDomain}
                      onChange={(e) => setEditPolicy({...editPolicy, requireDomain: e.target.checked})}
                      className="rounded text-indigo-600 focus:ring-indigo-500 w-4 h-4"
                    />
                    Requerir Dominio de Email
                  </label>
                  {editPolicy.requireDomain && (
                    <input 
                      type="text"
                      placeholder="Ej: escuela.com, alumnos.org"
                      value={editPolicy.allowedDomains}
                      onChange={(e) => setEditPolicy({...editPolicy, allowedDomains: e.target.value})}
                      className="w-full px-3 py-2 text-sm bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                  )}
                </div>

                {/* CODE SETTINGS */}
                <div className="space-y-3 p-4 bg-white/50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-700/50">
                  <label className="flex items-center gap-2 font-medium text-slate-700 dark:text-slate-300">
                    <input 
                      type="checkbox" 
                      checked={editPolicy.requireCode}
                      onChange={(e) => setEditPolicy({...editPolicy, requireCode: e.target.checked})}
                      className="rounded text-indigo-600 focus:ring-indigo-500 w-4 h-4"
                    />
                    Requerir Código Dinámico
                  </label>
                  {editPolicy.requireCode && (
                    <select
                      value={editPolicy.rotationIntervalHours}
                      onChange={(e) => setEditPolicy({...editPolicy, rotationIntervalHours: Number(e.target.value)})}
                      className="w-full px-3 py-2 text-sm bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500"
                    >
