                      <input
                        type="checkbox"
                        checked={editPolicy.canDeleteSubjectsWithStudents === true}
                        onChange={(e) => setEditPolicy({ ...editPolicy, canDeleteSubjectsWithStudents: e.target.checked })}
                        className="rounded text-indigo-600 focus:ring-indigo-500 w-4 h-4"
