// ─── InlineEditField ──────────────────────────────────────────────────────────
// Renders a read-only label that turns into an input when the pencil is clicked.
// Used for per-field editing inside detail views.
export const InlineEditField = ({
  label,
  displayValue,
  editingKey,
  fieldKey,
  onStartEdit,
  onCancelEdit,
  onSave,
  saving,
  children, // the actual input/select rendered when editing
}) => {
  const isEditing = editingKey === fieldKey;
  return (
    <div className="group py-3 border-b border-slate-100 dark:border-slate-800 last:border-0">
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0">
          <p className="text-xs font-semibold uppercase tracking-wider text-slate-400 mb-1">{label}</p>
          {isEditing ? (
            <div className="space-y-2 mt-1">
              {children}
              <div className="flex gap-2 mt-2">
                <button
                  onClick={() => onSave(fieldKey)}
                  disabled={saving}
                  className="flex items-center gap-1 px-3 py-1.5 text-xs font-semibold text-white rounded-lg transition-all disabled:opacity-60"
                  style={{ backgroundColor: '#6366f1' }}
                >
                  {saving ? '…' : '✓ Guardar'}
                </button>
                <button
                  onClick={onCancelEdit}
                  className="flex items-center gap-1 px-3 py-1.5 text-xs font-medium text-slate-500 bg-slate-100 dark:bg-slate-800 rounded-lg hover:bg-slate-200 transition-all"
                >
                  Cancelar
                </button>
              </div>
            </div>
          ) : (
            <p className="text-sm text-slate-800 dark:text-slate-200 leading-relaxed">
              {displayValue || <span className="italic text-slate-400">Sin especificar</span>}
            </p>
          )}
        </div>
        {!isEditing && (
          <button
            onClick={() => onStartEdit(fieldKey)}
            className="opacity-0 group-hover:opacity-100 p-1.5 rounded-lg text-slate-400
              hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/20 transition-all shrink-0 mt-0.5"
            title={`Editar ${label}`}
          >
            <Edit3 className="w-3.5 h-3.5" />
          </button>
        )}
      </div>
    </div>
  );
};

// src/pages/InstitutionAdminDashboard/hooks/useClassesCourses.js
// ─────────────────────────────────────────────────────────────────────────────
// All Firestore reads/writes for the Cursos & Clases section.
// Components stay pure – they only call functions from this hook.

import { useEffect, useState } from 'react';
import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDocs,
  query,
  serverTimestamp,
  updateDoc,
  where,
} from 'firebase/firestore';
import { db } from '../../../firebase/config';

export const useClassesCourses = (user, institutionIdOverride = null) => {
  const effectiveInstitutionId = institutionIdOverride || user?.institutionId || null;
  const [courses, setCourses] = useState([]);
  const [classes, setClasses] = useState([]);
  const [loading, setLoading] = useState(true);

  // ── Fetch ─────────────────────────────────────────────────────────────────
  const fetchAll = async () => {
    if (!effectiveInstitutionId) return;
    setLoading(true);
    try {
      const [cSnap, clSnap] = await Promise.all([
        getDocs(query(collection(db, 'courses'), where('institutionId', '==', effectiveInstitutionId))),
        getDocs(query(collection(db, 'classes'), where('institutionId', '==', effectiveInstitutionId))),
      ]);
      setCourses(cSnap.docs.map(d => ({ id: d.id, ...d.data() })));
      setClasses(clSnap.docs.map(d => ({ id: d.id, ...d.data() })));
    } catch (e) {
      console.error('useClassesCourses fetchAll:', e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchAll(); }, [effectiveInstitutionId]);

  // ── Course CRUD ───────────────────────────────────────────────────────────
  const createCourse = async (form) => {
    await addDoc(collection(db, 'courses'), {
      ...form,
      institutionId: effectiveInstitutionId,
      createdBy: user.uid,
      createdAt: serverTimestamp(),
    });
    await fetchAll();
  };

  const updateCourse = async (id, patch) => {
    await updateDoc(doc(db, 'courses', id), { ...patch, updatedAt: serverTimestamp() });
    await fetchAll();
  };

  const deleteCourse = async (id) => {
    await deleteDoc(doc(db, 'courses', id));
    await fetchAll();
  };

  // ── Class CRUD ────────────────────────────────────────────────────────────
  const createClass = async (form) => {
    await addDoc(collection(db, 'classes'), {
      ...form,
      institutionId: effectiveInstitutionId,
      createdBy: user.uid,
      createdAt: serverTimestamp(),
    });
    await fetchAll();
  };

  const updateClass = async (id, patch) => {
    await updateDoc(doc(db, 'classes', id), { ...patch, updatedAt: serverTimestamp() });
    await fetchAll();
  };

  const deleteClass = async (id) => {
    await deleteDoc(doc(db, 'classes', id));
    await fetchAll();
  };

  // ── Helpers ───────────────────────────────────────────────────────────────
  const getCourseById  = (id) => courses.find(c => c.id === id);
  const getTeacherById = (id, allTeachers) => allTeachers.find(t => t.id === id);
  const classesForCourse = (courseId) => classes.filter(cl => cl.courseId === courseId);

  return {
    courses, classes, loading, fetchAll,
    createCourse, updateCourse, deleteCourse,
    createClass,  updateClass,  deleteClass,
    getCourseById, getTeacherById, classesForCourse,
  };
};

// src/pages/InstitutionAdminDashboard/hooks/useCustomization.js
import { useState, useEffect } from 'react';
import { doc, getDoc, updateDoc, serverTimestamp } from 'firebase/firestore';
import { getDownloadURL, getStorage, ref, uploadBytes } from 'firebase/storage';
import { db } from '../../../firebase/config';
import {
  GLOBAL_BRAND_DEFAULTS,
  HOME_THEME_DEFAULT_COLORS,
  HOME_THEME_TOKENS,
  getEffectiveHomeThemeColors,
  normalizeHexColor,
  resolveInstitutionBranding,
} from '../../../utils/themeTokens';

export const DEFAULT_CUSTOMIZATION_FORM = {
  institutionDisplayName: '',
  iconUrl: '',
  logoUrl: '',
  primaryBrandColor: GLOBAL_BRAND_DEFAULTS.primaryColor,
  secondaryBrandColor: GLOBAL_BRAND_DEFAULTS.secondaryColor,
  tertiaryBrandColor: GLOBAL_BRAND_DEFAULTS.tertiaryColor,
  homeThemeColors: { ...HOME_THEME_DEFAULT_COLORS },
};

export const useCustomization = (user, institutionIdOverride = null) => {
  const effectiveInstitutionId = institutionIdOverride || user?.institutionId || null;
  const [institutionName, setInstitutionName] = useState('');
  const [customizationForm, setCustomizationForm] = useState(DEFAULT_CUSTOMIZATION_FORM);
  const [customizationLoading, setCustomizationLoading] = useState(false);
  const [customizationSaving, setCustomizationSaving] = useState(false);
  const [customizationError, setCustomizationError] = useState('');
  const [customizationSuccess, setCustomizationSuccess] = useState('');
  const [iconUploading, setIconUploading] = useState(false);
  const [iconUploadError, setIconUploadError] = useState('');

  // Favicon effect
  useEffect(() => {
    const iconUrl = customizationForm.iconUrl?.trim();
    if (!iconUrl) return;
    let faviconLink = document.querySelector('link[rel="icon"]');
    if (!faviconLink) {
      faviconLink = document.createElement('link');
      faviconLink.setAttribute('rel', 'icon');
      document.head.appendChild(faviconLink);
    }
    faviconLink.setAttribute('href', iconUrl);
  }, [customizationForm.iconUrl]);

  // Fetch customization from Firestore
  useEffect(() => {
    let active = true;
    const fetchInstitutionCustomization = async () => {
      if (!effectiveInstitutionId) return;
      setCustomizationLoading(true);
      try {
        const institutionRef = doc(db, 'institutions', effectiveInstitutionId);
        const institutionSnap = await getDoc(institutionRef);
        if (!active || !institutionSnap.exists()) return;

        const institutionData = institutionSnap.data() || {};
        const customizationData = institutionData.customization || {};
        const branding = resolveInstitutionBranding(institutionData);
        const resolvedColors = getEffectiveHomeThemeColors(
          customizationData.homeThemeColors || customizationData.home?.colors || null,
        );

        setInstitutionName(institutionData.name || '');
        setCustomizationForm({
          institutionDisplayName: branding.institutionDisplayName || institutionData.name || '',
          iconUrl: customizationData.iconUrl || '',
          logoUrl: branding.logoUrl || '',
          primaryBrandColor: branding.primaryColor || GLOBAL_BRAND_DEFAULTS.primaryColor,
          secondaryBrandColor: branding.secondaryColor || GLOBAL_BRAND_DEFAULTS.secondaryColor,
          tertiaryBrandColor: branding.tertiaryColor || GLOBAL_BRAND_DEFAULTS.tertiaryColor,
          homeThemeColors: resolvedColors,
        });
      } catch (error) {
        console.error('Error loading institution customization:', error);
        if (active) setCustomizationError('No se pudo cargar la personalización de la institución.');
      } finally {
        if (active) setCustomizationLoading(false);
      }
    };
    fetchInstitutionCustomization();
    return () => { active = false; };
  }, [effectiveInstitutionId]);

  const handleIconUpload = async (event) => {
    const file = event.target.files?.[0];
    event.target.value = '';
    if (!file || !effectiveInstitutionId) return;
    if (!file.type.startsWith('image/')) {
      setIconUploadError('Selecciona una imagen válida para el icono.');
      return;
    }
    setIconUploading(true);
    setIconUploadError('');
    setCustomizationError('');
    setCustomizationSuccess('');
    try {
      const fileExtension = file.name.includes('.') ? file.name.split('.').pop()?.toLowerCase() : 'png';
      const storageRef = ref(getStorage(db.app), `institutions/${effectiveInstitutionId}/branding/icon.${fileExtension || 'png'}`);
      await uploadBytes(storageRef, file, { contentType: file.type });
      const iconUrl = await getDownloadURL(storageRef);
      await updateDoc(doc(db, 'institutions', effectiveInstitutionId), {
        'customization.iconUrl': iconUrl,
        updatedAt: serverTimestamp(),
      });
      setCustomizationForm(prev => ({ ...prev, iconUrl }));
      setCustomizationSuccess('Icono guardado correctamente.');
    } catch (error) {
      console.error('Error uploading institution icon:', error);
      setIconUploadError('No se pudo subir el icono. Inténtalo de nuevo.');
    } finally {
      setIconUploading(false);
    }
  };

  const handleLogoUpload = async (event) => {
    const file = event.target.files?.[0];
    event.target.value = '';
    if (!file || !effectiveInstitutionId) return;
    if (!file.type.startsWith('image/')) {
      setIconUploadError('Selecciona una imagen válida para el logotipo.');
      return;
    }
    setIconUploading(true);
    setIconUploadError('');
    setCustomizationError('');
    setCustomizationSuccess('');
    try {
      const fileExtension = file.name.includes('.') ? file.name.split('.').pop()?.toLowerCase() : 'png';
      const storageRef = ref(getStorage(db.app), `institutions/${effectiveInstitutionId}/branding/logo.${fileExtension || 'png'}`);
      await uploadBytes(storageRef, file, { contentType: file.type });
      const logoUrl = await getDownloadURL(storageRef);
      await updateDoc(doc(db, 'institutions', effectiveInstitutionId), {
        'customization.logoUrl': logoUrl,
        updatedAt: serverTimestamp(),
      });
      setCustomizationForm(prev => ({ ...prev, logoUrl }));
      setCustomizationSuccess('Logotipo guardado correctamente.');
    } catch (error) {
      setIconUploadError('No se pudo subir el logotipo. Inténtalo de nuevo.');
    } finally {
      setIconUploading(false);
    }
  };

  const handleLogoUrlSave = async (url) => {
    if (!url || !effectiveInstitutionId) return;
    try {
      await updateDoc(doc(db, 'institutions', effectiveInstitutionId), {
        'customization.logoUrl': url,
        updatedAt: serverTimestamp(),
      });
      setCustomizationForm(prev => ({ ...prev, logoUrl: url }));
    } catch (error) {
      setCustomizationError('No se pudo guardar el logo por URL. Inténtalo de nuevo.');
    }
  };

  const handleSaveCustomization = async (incomingFormValues = null) => {
    if (!effectiveInstitutionId) return;

    const nextCustomizationForm = incomingFormValues
      ? {
          institutionDisplayName: incomingFormValues.institutionName || '',
          iconUrl: customizationForm.iconUrl || '',
          logoUrl: incomingFormValues.logoUrl || '',
          primaryBrandColor: incomingFormValues.primary || GLOBAL_BRAND_DEFAULTS.primaryColor,
          secondaryBrandColor: incomingFormValues.secondary || GLOBAL_BRAND_DEFAULTS.secondaryColor,
          tertiaryBrandColor: incomingFormValues.accent || GLOBAL_BRAND_DEFAULTS.tertiaryColor,
          homeThemeColors: getEffectiveHomeThemeColors({
            primary: incomingFormValues.primary,
            secondary: incomingFormValues.secondary,
            accent: incomingFormValues.accent,
            mutedText: HOME_THEME_DEFAULT_COLORS.mutedText,
            cardBorder: incomingFormValues.cardBorder,
            cardBackground: HOME_THEME_DEFAULT_COLORS.cardBackground,
          }),
        }
      : customizationForm;

    setCustomizationError('');
    setCustomizationSuccess('');
    setCustomizationSaving(true);

    try {
      const institutionRef = doc(db, 'institutions', effectiveInstitutionId);
      const resolvedColors = getEffectiveHomeThemeColors(nextCustomizationForm.homeThemeColors);
      const normalizedPrimaryBrandColor = normalizeHexColor(nextCustomizationForm.primaryBrandColor) || GLOBAL_BRAND_DEFAULTS.primaryColor;
      const normalizedSecondaryBrandColor = normalizeHexColor(nextCustomizationForm.secondaryBrandColor) || GLOBAL_BRAND_DEFAULTS.secondaryColor;
      const normalizedTertiaryBrandColor = normalizeHexColor(nextCustomizationForm.tertiaryBrandColor) || GLOBAL_BRAND_DEFAULTS.tertiaryColor;

      await updateDoc(institutionRef, {
        'customization.institutionDisplayName': nextCustomizationForm.institutionDisplayName.trim() || institutionName || '',
        'customization.iconUrl': nextCustomizationForm.iconUrl.trim(),
        'customization.logoUrl': nextCustomizationForm.logoUrl.trim(),
        'customization.primaryBrandColor': normalizedPrimaryBrandColor,
        'customization.secondaryBrandColor': normalizedSecondaryBrandColor,
        'customization.tertiaryBrandColor': normalizedTertiaryBrandColor,
        'customization.brand.primaryColor': normalizedPrimaryBrandColor,
        'customization.brand.secondaryColor': normalizedSecondaryBrandColor,
        'customization.brand.tertiaryColor': normalizedTertiaryBrandColor,
        'customization.homeThemeColors': resolvedColors,
        'customization.home.colors': resolvedColors,
        'customization.homeThemeTokens': HOME_THEME_TOKENS,
        'customization.home.tokens': HOME_THEME_TOKENS,
        updatedAt: serverTimestamp(),
      });

      setCustomizationForm(nextCustomizationForm);
      setCustomizationSuccess('Personalización guardada correctamente.');
    } catch (error) {
      console.error('Error saving customization:', error);
      setCustomizationError('No se pudieron guardar los cambios. Inténtalo de nuevo.');
      throw error;
    } finally {
      setCustomizationSaving(false);
    }
  };

  const customizationInitialValues = {
    institutionName: customizationForm.institutionDisplayName || institutionName || '',
    logoUrl: customizationForm.logoUrl || '',
    primary: customizationForm.primaryBrandColor || customizationForm.homeThemeColors?.primary || HOME_THEME_DEFAULT_COLORS.primary,
    secondary: customizationForm.secondaryBrandColor || customizationForm.homeThemeColors?.secondary || GLOBAL_BRAND_DEFAULTS.secondaryColor,
    accent: customizationForm.tertiaryBrandColor || customizationForm.homeThemeColors?.accent || GLOBAL_BRAND_DEFAULTS.tertiaryColor,
    mutedText: HOME_THEME_DEFAULT_COLORS.mutedText,
    cardBorder: customizationForm.homeThemeColors?.cardBorder || HOME_THEME_DEFAULT_COLORS.cardBorder,
    cardBackground: HOME_THEME_DEFAULT_COLORS.cardBackground,
  };

  return {
    institutionName,
    customizationForm,
    setCustomizationForm,
    customizationLoading,
    customizationSaving,
    customizationError,
    customizationSuccess,
    iconUploading,
    iconUploadError,
    handleIconUpload,
    handleLogoUpload,
    handleLogoUrlSave,
    handleSaveCustomization,
    customizationInitialValues,
  };
};

// src/pages/InstitutionAdminDashboard/hooks/useUsers.js
import { useState, useEffect } from 'react';
import {
  addDoc,
  collection,
  deleteDoc,
  doc,
  getDoc,
  getDocs,
  query,
  serverTimestamp,
  setDoc,
  updateDoc,
  where,
  writeBatch,
} from 'firebase/firestore';
import { db } from '../../../firebase/config';
import { getInstitutionalAccessCodePreview } from '../../../services/accessCodeService';
import { DEFAULT_ACCESS_POLICIES, normalizeAccessPolicies } from '../../../utils/institutionPolicyUtils';
import { usePersistentState } from '../../../hooks/usePersistentState';
import { buildInstitutionScopedPersistenceKey } from '../../../utils/pagePersistence';

export const useUsers = (user, institutionIdOverride = null) => {
  const effectiveInstitutionId = institutionIdOverride || user?.institutionId || null;
  const userTypeKey = buildInstitutionScopedPersistenceKey('institution-admin-users', effectiveInstitutionId, 'user-type');
  const [userType, setUserType] = usePersistentState(userTypeKey, 'teachers');
  const [teachers, setTeachers] = useState([]);
  const [students, setStudents] = useState([]);
  const [allowedTeachers, setAllowedTeachers] = useState([]);
  const [allTeachers, setAllTeachers] = useState([]);
  const [allStudents, setAllStudents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');

  const [showAddUserModal, setShowAddUserModal] = useState(false);
  const [newUserEmail, setNewUserEmail] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [addError, setAddError] = useState('');
  const [addSuccess, setAddSuccess] = useState('');

  const [institutionalCode, setInstitutionalCode] = useState('');
  const [isUpdatingCode, setIsUpdatingCode] = useState(false);
  const [liveAccessCode, setLiveAccessCode] = useState('');
  const [liveCodeLoading, setLiveCodeLoading] = useState(false);
  const [liveCodeError, setLiveCodeError] = useState('');
  const [codeUpdateSuccess, setCodeUpdateSuccess] = useState('');
  const [codeUpdateError, setCodeUpdateError] = useState('');

  const [accessPolicies, setAccessPolicies] = useState(DEFAULT_ACCESS_POLICIES);
  const [isUpdatingPolicies, setIsUpdatingPolicies] = useState(false);
  const [policyMessage, setPolicyMessage] = useState({ type: '', text: '' });
  const [showSudoModal, setShowSudoModal] = useState(false);
  const [pendingPolicies, setPendingPolicies] = useState(null);

  const fetchData = async () => {
    if (!effectiveInstitutionId) return;
    setLoading(true);
    try {
      if (userType === 'teachers') {
        const [teachersSnap, allowedSnap] = await Promise.all([
          getDocs(query(collection(db, 'users'), where('institutionId', '==', effectiveInstitutionId), where('role', '==', 'teacher'))),
          getDocs(query(collection(db, 'institution_invites'), where('institutionId', '==', effectiveInstitutionId))),
        ]);
        setTeachers(teachersSnap.docs.map(d => ({ id: d.id, ...d.data() })));
        setAllowedTeachers(allowedSnap.docs.map(d => ({ id: d.id, ...d.data() })));
        const generalInvite = allowedSnap.docs.find(d => d.data().type === 'institutional');
        setInstitutionalCode(generalInvite ? generalInvite.id : '');
        setStudents([]);
      } else {
        const studentsSnap = await getDocs(query(collection(db, 'users'), where('institutionId', '==', effectiveInstitutionId), where('role', '==', 'student')));
        setStudents(studentsSnap.docs.map(d => ({ id: d.id, ...d.data() })));
        setTeachers([]);
        setAllowedTeachers([]);
      }
      const instDoc = await getDoc(doc(db, 'institutions', effectiveInstitutionId));
      if (instDoc.exists()) {
        setAccessPolicies(normalizeAccessPolicies(instDoc.data().accessPolicies));
      } else {
        setAccessPolicies(DEFAULT_ACCESS_POLICIES);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [user, userType, effectiveInstitutionId]);

  // Live access code polling
  useEffect(() => {
    let cancelled = false;
    let intervalId = null;

    const refreshLiveCode = async () => {
      if (!effectiveInstitutionId) return;
      const policy = accessPolicies?.[userType] || { requireCode: true, rotationIntervalHours: 24 };
      if (policy.requireCode === false) {
        if (!cancelled) { setLiveAccessCode(''); setLiveCodeError(''); }
        return;
      }
      setLiveCodeLoading(true);
      setLiveCodeError('');
      try {
        const preview = await getInstitutionalAccessCodePreview({
          institutionId: effectiveInstitutionId,
          userType: userType === 'students' ? 'student' : 'teacher',
          intervalHours: Number(policy.rotationIntervalHours || 24),
        });
        if (!cancelled) setLiveAccessCode(preview?.code || '------');
      } catch {
        if (!cancelled) { setLiveAccessCode('------'); setLiveCodeError('No se pudo obtener el código en este momento.'); }
      } finally {
        if (!cancelled) setLiveCodeLoading(false);
      }
    };

    refreshLiveCode();
    intervalId = setInterval(refreshLiveCode, 30000);
    return () => { cancelled = true; if (intervalId) clearInterval(intervalId); };
  }, [effectiveInstitutionId, userType, accessPolicies]);

  // Fetch all teachers/students for org view
  useEffect(() => {
    if (!effectiveInstitutionId) return;
    Promise.all([
      getDocs(query(collection(db, 'users'), where('institutionId', '==', effectiveInstitutionId), where('role', '==', 'teacher'))),
      getDocs(query(collection(db, 'users'), where('institutionId', '==', effectiveInstitutionId), where('role', '==', 'student'))),
    ]).then(([teachersSnap, studentsSnap]) => {
      setAllTeachers(teachersSnap.docs.map(d => ({ id: d.id, ...d.data() })));
      setAllStudents(studentsSnap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
  }, [user, effectiveInstitutionId]);

  const handleAddUser = async (e) => {
    e.preventDefault();
    const normalizedEmail = newUserEmail.toLowerCase().trim();
    if (!normalizedEmail) return;
    setIsSubmitting(true);
    setAddError('');
    setAddSuccess('');
    try {
      const qUser = query(collection(db, 'users'), where('email', '==', normalizedEmail), where('institutionId', '==', effectiveInstitutionId));
      const existingUserSnap = await getDocs(qUser);
      if (!existingUserSnap.empty) {
        setAddError('Este profesor ya está registrado y activo en tu institución.');
        return;
      }
      const qInvite = query(collection(db, 'institution_invites'), where('email', '==', normalizedEmail), where('institutionId', '==', effectiveInstitutionId));
      const existingInviteSnap = await getDocs(qInvite);
      if (!existingInviteSnap.empty) {
        setAddError('Este profesor ya tiene una invitación pendiente.');
        return;
      }
      await addDoc(collection(db, 'institution_invites'), {
        email: normalizedEmail,
        institutionId: effectiveInstitutionId,
        role: 'teacher',
        type: 'direct',
        createdAt: serverTimestamp(),
      });
      setAddSuccess('Profesor invitado correctamente. Puede copiar el código de acceso en la tabla.');
      setNewUserEmail('');
      setTimeout(() => setShowAddUserModal(false), 2000);
      fetchData();
    } catch (error) {
      console.error('Error adding user:', error);
      setAddError('Ocurrió un error al invitar al profesor.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleUpdateInstitutionalCode = async (newCode) => {
    if (!newCode.trim()) return;
    const finalCode = newCode.trim().toUpperCase();
    setIsUpdatingCode(true);
    setCodeUpdateSuccess('');
    setCodeUpdateError('');
    try {
      const q = query(collection(db, 'institution_invites'), where('institutionId', '==', effectiveInstitutionId), where('type', '==', 'institutional'));
      const snap = await getDocs(q);
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
      await setDoc(doc(db, 'institution_invites', finalCode), {
        institutionId: effectiveInstitutionId,
        role: 'teacher',
        type: 'institutional',
        createdAt: serverTimestamp(),
      });
      setInstitutionalCode(finalCode);
      fetchData();
      setCodeUpdateSuccess('Código actualizado con éxito.');
      setTimeout(() => setCodeUpdateSuccess(''), 4000);
    } catch (error) {
      console.error('Error updating code:', error);
      setCodeUpdateError('Este código ya está en uso. Intenta con otro.');
      setTimeout(() => setCodeUpdateError(''), 5000);
    } finally {
      setIsUpdatingCode(false);
    }
  };

  const handleSavePolicies = (updatedPolicies) => {
    setPendingPolicies(updatedPolicies);
    setPolicyMessage({ type: '', text: '' });
    setShowSudoModal(true);
  };

  const handleConfirmSavePolicies = async () => {
    if (!pendingPolicies) return;
    setIsUpdatingPolicies(true);
    setPolicyMessage({ type: '', text: '' });
    try {
      const normalizedPolicies = normalizeAccessPolicies(pendingPolicies);
      await updateDoc(doc(db, 'institutions', effectiveInstitutionId), { accessPolicies: normalizedPolicies });
      setAccessPolicies(normalizedPolicies);
      setPendingPolicies(null);
      setPolicyMessage({ type: 'success', text: 'Políticas de acceso actualizadas correctamente.' });
      setTimeout(() => setPolicyMessage({ type: '', text: '' }), 4000);
    } catch (error) {
      console.error('Error saving policies:', error);
      setPolicyMessage({ type: 'error', text: 'Error al guardar las políticas.' });
    } finally {
      setIsUpdatingPolicies(false);
    }
  };

  const handleRemoveAccess = async (docId) => {
    if (!docId) return;

    try {
      await deleteDoc(doc(db, 'institution_invites', docId));
      fetchData();
    } catch (error) {
      console.error('Error removing access', error);
    }
  };

  return {
    userType, setUserType,
    effectiveInstitutionId,
    teachers, students, allowedTeachers, allTeachers, allStudents,
    loading, searchTerm, setSearchTerm,
    showAddUserModal, setShowAddUserModal,
    newUserEmail, setNewUserEmail,
    isSubmitting, addError, addSuccess,
    institutionalCode, isUpdatingCode,
    liveAccessCode, liveCodeLoading, liveCodeError,
    codeUpdateSuccess, codeUpdateError,
    accessPolicies, isUpdatingPolicies, policyMessage,
    showSudoModal, setShowSudoModal,
    pendingPolicies,
    handleAddUser,
    handleUpdateInstitutionalCode,
    handleSavePolicies,
    handleConfirmSavePolicies,
    handleRemoveAccess,
  };
};

// src/pages/Onboarding/components/OnboardingWizard.jsx
import React, { useState, useEffect } from 'react';
import { Loader2, GraduationCap, Key, User, AlertCircle, ArrowLeft } from 'lucide-react';
import { doc, setDoc, serverTimestamp } from 'firebase/firestore';
import { httpsCallable } from 'firebase/functions';
import { db, functions } from '../../../firebase/config'; 
import UserTypeSelector from '../../Auth/components/UserTypeSelector'; 

const OnboardingWizard = ({ user }) => {
    const [missingFields, setMissingFields] = useState([]);
    const [show, setShow] = useState(false);
    const [stepIndex, setStepIndex] = useState(0);
    const [tempData, setTempData] = useState({});
    const [saving, setSaving] = useState(false);
    
    // Estados para la validación del código
    const [validating, setValidating] = useState(false);
    const [codeError, setCodeError] = useState("");
    const [accessCode, setAccessCode] = useState('');

    const [attempts, setAttempts] = useState(0);
    const [lockoutTime, setLockoutTime] = useState(0);
    const currentField = missingFields[stepIndex];

    useEffect(() => {
        if (!user) return;
        const required = ['role', 'institutionId', 'displayName'];
        const missing = required.filter((key) => !user[key] || user[key] === '');
        setMissingFields(missing);
        setShow(missing.length > 0);
        setStepIndex((prev) => {
            if (missing.length === 0) return 0;
            return Math.min(prev, missing.length - 1);
        });
    }, [user]);

    const handleAnswer = async (key, value) => {
        const updated = { ...tempData, [key]: value };
        setTempData(updated);

        if (stepIndex < missingFields.length - 1) {
            setStepIndex(prev => prev + 1);
        } else {
            setSaving(true);
            try {
                await setDoc(doc(db, "users", user.uid), {
                    ...updated,
                    uid: user.uid,
                    email: user.email,
                    lastLogin: serverTimestamp()
                }, { merge: true });
                setShow(false);
                window.location.reload();
            } catch (error) {
                console.error("Error saving profile", error);
            } finally {
                setSaving(false);
            }
        }
    };

    // Función para ir al paso anterior
    const handleBack = () => {
        if (stepIndex > 0) {
            setStepIndex(prev => prev - 1);
            setCodeError(""); // Limpiamos errores por si acaso
        }
    };

    // Temporizador para el bloqueo
    useEffect(() => {
        if (lockoutTime > 0) {
            const timer = setTimeout(() => setLockoutTime(prev => prev - 1), 1000);
            return () => clearTimeout(timer);
        }
    }, [lockoutTime]);

    useEffect(() => {
        if (currentField !== 'institutionId') {
            setAccessCode('');
            return;
        }
        setAccessCode(prev => String(prev || '').toUpperCase());
    }, [currentField]);

    const handleCodeValidation = async (e) => {
        e.preventDefault();
        if (lockoutTime > 0) return;

        const code = String(accessCode || '').trim().toUpperCase();
        if (!code) {
            setCodeError("Introduce un código válido.");
            return;
        }
        setValidating(true);
        setCodeError("");

        try {
            const validateFn = httpsCallable(functions, 'validateInstitutionalAccessCode');
            const result = await validateFn({ 
                verificationCode: code, 
                userType: tempData.role,
                email: user.email // Enviamos el email para validar el dominio en el backend
            });

            if (result.data && result.data.institutionId) {
                // ÉXITO
                handleAnswer('institutionId', result.data.institutionId);
            } else {
                throw new Error("Invalid");
            }
        } catch (error) {
            // LÓGICA DE BLOQUEO
            const newAttempts = attempts + 1;
            setAttempts(newAttempts);
            
            if (newAttempts >= 3) {
                setLockoutTime(30 * (newAttempts - 2)); // 30s, 60s, 90s...
                setCodeError(`Demasiados intentos. Espera ${30 * (newAttempts - 2)} segundos.`);
            } else {
                setCodeError("Código no válido. Revisa que sea el correcto para tu rol.");
            }
        } finally {
            setValidating(false);
        }
    };

    if (!show) return null;

    return (
        <div className="fixed inset-0 z-[9999] bg-slate-900/95 backdrop-blur-md flex items-center justify-center p-4">
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-2xl p-8 max-w-md w-full relative overflow-hidden border border-transparent dark:border-slate-800">
                
                {/* Progress Bar */}
                <div className="absolute top-0 left-0 h-2 bg-indigo-100 dark:bg-slate-800 w-full">
                    <div 
                        className="h-full bg-indigo-600 transition-all duration-500" 
                        style={{ width: `${((stepIndex + 1) / missingFields.length) * 100}%` }} 
                    />
                </div>

                {/* Botón de ir atrás */}
                {stepIndex > 0 && !saving && (
                    <button 
                        onClick={handleBack}
                        className="absolute top-6 left-6 p-2 text-gray-400 hover:text-gray-700 dark:text-gray-500 dark:hover:text-gray-300 transition-colors rounded-full hover:bg-gray-100 dark:hover:bg-slate-800"
                        title="Volver al paso anterior"
                    >
                        <ArrowLeft size={24} />
                    </button>
                )}

                {saving ? (
                    <div className="flex flex-col items-center py-8">
                        <Loader2 className="w-12 h-12 text-indigo-600 animate-spin mb-4" />
                        <p className="text-lg font-medium text-gray-700 dark:text-gray-300">Configurando tu cuenta...</p>
                    </div>
                ) : (
                    <>
                        {currentField === 'role' && (
                            <div className="animate-fadeIn mt-4">
                                <div className="flex justify-center mb-4"><GraduationCap size={48} className="text-indigo-600 dark:text-indigo-400"/></div>
                                <h3 className="text-2xl font-bold text-center mb-6 text-gray-900 dark:text-white">¿Cuál es tu rol?</h3>
                                
                                <UserTypeSelector 
                                    selectedType={tempData.role} 
                                    onSelect={(val) => handleAnswer('role', val)} 
                                />
                            </div>
                        )}

                        {currentField === 'institutionId' && (
                            <div className="animate-fadeIn mt-4">
                                <div className="flex justify-center mb-4"><Key size={48} className="text-emerald-600 dark:text-emerald-400"/></div>
                                <h3 className="text-2xl font-bold text-center mb-2 text-gray-900 dark:text-white">Código de acceso</h3>
                                <p className="text-center text-gray-500 dark:text-gray-400 mb-6 text-sm">
                                    Introduce el código que te ha proporcionado tu institución.
                                </p>
                                
                                {codeError && (
                                    <div className="mb-4 p-3 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-800 rounded-lg flex items-center gap-2 text-red-600 dark:text-red-400 text-sm">
                                        <AlertCircle size={16} />
                                        {codeError}
                                    </div>
                                )}

                                <form onSubmit={handleCodeValidation} className="space-y-4">
                                    <input 
                                        name="code" 
                                        placeholder="Introduce tu código" 
                                        value={accessCode}
                                        onChange={(event) => {
                                            setAccessCode(String(event.target.value || '').toUpperCase());
                                            if (codeError) setCodeError('');
                                        }}
                                        onPaste={(event) => {
                                            const clipboardText = event.clipboardData?.getData('text') || '';
                                            if (!clipboardText) return;
                                            event.preventDefault();
                                            setAccessCode(String(clipboardText).trim().toUpperCase());
                                            if (codeError) setCodeError('');
                                        }}
                                        className="w-full p-4 text-center text-2xl tracking-widest font-mono border dark:border-slate-700 rounded-lg bg-gray-50 dark:bg-slate-800 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 uppercase" 
                                        required 
                                        disabled={validating || lockoutTime > 0}
                                        autoComplete="off"
                                    />
                                    <button 
                                        type="submit" 
                                        disabled={validating || lockoutTime > 0}
                                        className="w-full bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-500 text-white py-3 rounded-lg font-bold transition-colors flex justify-center items-center gap-2"
                                    >
                                        {validating ? <Loader2 className="w-5 h-5 animate-spin" /> : (lockoutTime > 0 ? `Bloqueado (${lockoutTime}s)` : "Validar")}
                                    </button>
                                </form>
                            </div>
                        )}

                        {currentField === 'displayName' && (
                            <div className="animate-fadeIn mt-4">
                                <div className="flex justify-center mb-4"><User size={48} className="text-blue-600 dark:text-blue-400"/></div>
                                <h3 className="text-2xl font-bold text-center mb-2 text-gray-900 dark:text-white">¿Cómo te llamas?</h3>
                                <p className="text-center text-gray-500 dark:text-gray-400 mb-6 text-sm">
                                    Este es el nombre que verán tus compañeros y profesores.
                                </p>
                                <form 
                                    onSubmit={(e) => { 
                                        e.preventDefault(); 
                                        const fd = new FormData(e.target); 
                                        handleAnswer('displayName', `${fd.get('fname')} ${fd.get('lname')}`); 
                                    }} 
                                    className="space-y-4"
                                >
                                    <input 
                                        name="fname" 
                                        placeholder="Nombre" 
                                        className="w-full p-3 border dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-blue-500" 
                                        required 
                                    />
                                    <input 
                                        name="lname" 
                                        placeholder="Apellidos" 
                                        className="w-full p-3 border dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-gray-900 dark:text-white outline-none focus:ring-2 focus:ring-blue-500" 
                                        required 
                                    />
                                    <button 
                                        type="submit" 
                                        className="w-full bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-lg font-bold transition-colors"
                                    >
                                        Completar perfil
                                    </button>
                                </form>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
};

export default OnboardingWizard;

// src/pages/Profile/components/FinalGrades.jsx
import React, { useState } from 'react';
import { ClipboardList, ChevronDown, ChevronUp, ArrowRight, TrendingUp, CheckCircle2, XCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

/**
 * FinalGrades
 * 
 * Props:
 *   - subjectPerformance: array of { id, name, color, average, passRate, quizCount }
 *   - role: 'student' | 'teacher'
 *   - recentActivity: array of { id, quizTitle, subjectName, score, passed, date }
 *   - teacherDashboardPath: string (path to redirect teacher)
 */

const gradeLabel = (score) => {
    if (score >= 90) return { label: 'Sobresaliente', color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/20' };
    if (score >= 70) return { label: 'Notable', color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/20' };
    if (score >= 60) return { label: 'Bien', color: 'text-sky-600 dark:text-sky-400', bg: 'bg-sky-50 dark:bg-sky-900/20' };
    if (score >= 50) return { label: 'Aprobado', color: 'text-amber-600 dark:text-amber-400', bg: 'bg-amber-50 dark:bg-amber-900/20' };
    return { label: 'Suspenso', color: 'text-red-600 dark:text-red-400', bg: 'bg-red-50 dark:bg-red-900/20' };
};

const ScoreRing = ({ score, size = 48 }) => {
    const radius = (size - 6) / 2;
    const circumference = 2 * Math.PI * radius;
    const strokeDash = (score / 100) * circumference;
    const { color } = gradeLabel(score);
    const strokeColor = score >= 70 ? '#22c55e' : score >= 50 ? '#f59e0b' : '#ef4444';

    return (
        <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
            <svg width={size} height={size} style={{ transform: 'rotate(-90deg)' }}>
                <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke="currentColor" strokeWidth="3" className="text-gray-100 dark:text-gray-700" />
                <circle cx={size / 2} cy={size / 2} r={radius} fill="none" stroke={strokeColor} strokeWidth="3"
                    strokeDasharray={`${strokeDash} ${circumference}`} strokeLinecap="round" />
            </svg>
            <span className={`absolute text-xs font-bold ${color}`}>{score}</span>
        </div>
    );
};

const FinalGrades = ({
    subjectPerformance = [],
    role = 'student',
    recentActivity = [],
    teacherDashboardPath = '/dashboard/stats',
}) => {
    const [expanded, setExpanded] = useState(false);
    const navigate = useNavigate ? useNavigate() : null;

    const overallAvg = subjectPerformance.length > 0
        ? Math.round(subjectPerformance.reduce((a, b) => a + b.average, 0) / subjectPerformance.length)
        : null;

    const { label: overallLabel, color: overallColor, bg: overallBg } = overallAvg !== null ? gradeLabel(overallAvg) : { label: '--', color: 'text-gray-400', bg: '' };

    const handleNavigate = () => {
        if (navigate) navigate(teacherDashboardPath);
    };

    return (
        <div className="bg-white dark:bg-gray-800 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-sm transition-colors overflow-hidden">
            {/* Header - always visible */}
            <button
                className="w-full flex items-center justify-between px-6 py-4 hover:bg-gray-50 dark:hover:bg-gray-700/40 transition-colors"
                onClick={() => setExpanded(e => !e)}
            >
                <div className="flex items-center gap-3">
                    <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-indigo-500 to-violet-500 flex items-center justify-center shadow-md shadow-indigo-400/30">
                        <ClipboardList className="w-5 h-5 text-white" />
                    </div>
                    <div className="text-left">
                        <h3 className="text-sm font-bold text-gray-800 dark:text-gray-100">
                            {role === 'teacher' ? 'Estadísticas Generales' : 'Notas Finales'}
                        </h3>
                        <p className="text-xs text-gray-400 dark:text-gray-500">
                            {subjectPerformance.length} asignaturas
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    {overallAvg !== null && (
                        <div className={`px-3 py-1 rounded-full text-xs font-bold ${overallColor} ${overallBg}`}>
                            {overallAvg}% · {overallLabel}
                        </div>
                    )}
                    {expanded ? <ChevronUp className="w-4 h-4 text-gray-400" /> : <ChevronDown className="w-4 h-4 text-gray-400" />}
                </div>
            </button>

            {/* Expanded content */}
            {expanded && (
                <div className="border-t border-gray-100 dark:border-gray-700">
                    {subjectPerformance.length === 0 ? (
                        <div className="px-6 py-8 text-center text-sm text-gray-400 dark:text-gray-500">
                            No hay datos de notas disponibles.
                        </div>
                    ) : (
                        <>
                            {/* Subject grades list */}
                            <div className="divide-y divide-gray-50 dark:divide-gray-700/50">
                                {subjectPerformance.map((sub) => {
                                    const { label, color, bg } = gradeLabel(sub.average);
                                    return (
                                        <div key={sub.id} className="flex items-center gap-4 px-6 py-3 hover:bg-gray-50/50 dark:hover:bg-gray-700/20 transition-colors">
                                            <ScoreRing score={sub.average} size={44} />

                                            <div className="flex-1 min-w-0">
                                                <div className="flex items-center justify-between gap-2">
                                                    <span className="text-sm font-semibold text-gray-800 dark:text-gray-200 truncate">{sub.name}</span>
                                                    <span className={`text-xs font-bold px-2 py-0.5 rounded-full shrink-0 ${color} ${bg}`}>{label}</span>
                                                </div>
                                                <div className="flex items-center gap-3 mt-1">
                                                    <span className="text-xs text-gray-400 dark:text-gray-500">{sub.quizCount} tests</span>
                                                    <div className="flex items-center gap-1 text-xs text-gray-400 dark:text-gray-500">
                                                        {sub.passRate >= 70
                                                            ? <CheckCircle2 className="w-3 h-3 text-emerald-500" />
                                                            : <XCircle className="w-3 h-3 text-red-400" />}
                                                        {sub.passRate}% aprobados
                                                    </div>
                                                </div>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>

                            {/* Recent activity snippet */}
                            {recentActivity.length > 0 && (
                                <div className="px-6 py-3 border-t border-gray-100 dark:border-gray-700 bg-gray-50/50 dark:bg-gray-700/10">
                                    <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 mb-2 flex items-center gap-1.5">
                                        <TrendingUp className="w-3.5 h-3.5" />
                                        Últimas actividades
                                    </p>
                                    <div className="space-y-1.5">
                                        {recentActivity.slice(0, 3).map((a) => (
                                            <div key={a.id} className="flex items-center justify-between text-xs">
                                                <span className="text-gray-600 dark:text-gray-300 truncate max-w-[60%]">{a.quizTitle}</span>
                                                <span className={`font-bold ${a.passed ? 'text-emerald-600 dark:text-emerald-400' : 'text-red-500'}`}>{a.score}%</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            {/* CTA for teacher */}
                            {role === 'teacher' && (
                                <div className="px-6 py-3 border-t border-gray-100 dark:border-gray-700 flex justify-end">
                                    <button
                                        onClick={handleNavigate}
                                        className="flex items-center gap-2 text-xs font-semibold text-indigo-600 dark:text-indigo-400 hover:underline"
                                    >
                                        Ver estadísticas detalladas
                                        <ArrowRight className="w-3.5 h-3.5" />
                                    </button>
                                </div>
                            )}
                        </>
                    )}
                </div>
            )}
        </div>
    );
};

export default FinalGrades;

// src/pages/Profile/components/MiniStatsChart.jsx
import React, { useState, useMemo } from 'react';
import { TrendingUp, TrendingDown, Minus, X, Calendar } from 'lucide-react';

const PERIODS = [
    { key: 'all',    label: 'Todo' },
    { key: '30d',    label: '30 días' },
    { key: '90d',    label: '90 días' },
    { key: '7d',     label: '7 días' },
];

const getBarColor = (score) => {
    if (score >= 85) return { bar: '#22c55e', glow: 'rgba(34,197,94,0.4)' };
    if (score >= 70) return { bar: '#4ade80', glow: 'rgba(74,222,128,0.3)' };
    if (score >= 55) return { bar: '#f59e0b', glow: 'rgba(245,158,11,0.3)' };
    if (score >= 40) return { bar: '#f97316', glow: 'rgba(249,115,22,0.3)' };
    return { bar: '#ef4444', glow: 'rgba(239,68,68,0.3)' };
};

const filterByPeriod = (data, period) => {
    if (period === 'all') return data;
    const now = new Date();
    const days = period === '7d' ? 7 : period === '30d' ? 30 : 90;
    const cutoff = new Date(now.getTime() - days * 24 * 60 * 60 * 1000);
    return data.filter(d => d.date >= cutoff);
};

// ─── Detailed Overlay Chart ───────────────────────────────────────────────────
const ChartOverlay = ({ data, role, onClose }) => {
    const [period, setPeriod] = useState('all');
    const [hoveredIdx, setHoveredIdx] = useState(null);

    const filtered = useMemo(() => filterByPeriod(data, period).sort((a, b) => a.date - b.date), [data, period]);
    const scores = filtered.map(d => d.score);
    const avg = scores.length > 0 ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : 0;
    const best = scores.length > 0 ? Math.max(...scores) : 0;
    const worst = scores.length > 0 ? Math.min(...scores) : 0;
    const passed = filtered.filter(d => d.score >= 50).length;

    // Sparkline SVG
    const W = 600; const H = 120;
    const points = scores.map((s, i) => ({
        x: scores.length > 1 ? (i / (scores.length - 1)) * W : W / 2,
        y: H - (s / 100) * H
    }));
    const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(' ');
    const areaD = points.length > 0
        ? `${pathD} L ${points[points.length - 1].x.toFixed(1)} ${H} L ${points[0].x.toFixed(1)} ${H} Z`
        : '';

    const lineColor = avg >= 70 ? '#22c55e' : avg >= 50 ? '#f59e0b' : '#ef4444';

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm" onClick={onClose}>
            <div
                className="bg-white dark:bg-gray-900 rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden animate-fadeIn"
                onClick={e => e.stopPropagation()}
            >
                {/* Header */}
                <div className="flex items-center justify-between px-6 py-5 border-b border-gray-100 dark:border-gray-800">
                    <div className="flex items-center gap-3">
                        <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-emerald-500 to-teal-400 flex items-center justify-center shadow-md">
                            <TrendingUp className="w-5 h-5 text-white" />
                        </div>
                        <div>
                            <h3 className="font-bold text-gray-900 dark:text-gray-100">Evolución de notas</h3>
                            <p className="text-xs text-gray-400 dark:text-gray-500">
                                {role === 'teacher' ? 'Media de todos los alumnos' : `${filtered.length} tests en el período seleccionado`}
                            </p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 rounded-xl text-gray-400 hover:text-gray-700 dark:hover:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                <div className="p-6 space-y-5">
                    {/* Period selector */}
                    <div className="flex items-center gap-2">
                        <Calendar className="w-4 h-4 text-gray-400" />
                        <div className="flex gap-1.5">
                            {PERIODS.map(p => (
                                <button
                                    key={p.key}
                                    onClick={() => setPeriod(p.key)}
                                    className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${
                                        period === p.key
                                        ? 'bg-indigo-600 text-white shadow-sm'
                                        : 'bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700'
                                    }`}
                                >
                                    {p.label}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* KPI row */}
                    <div className="grid grid-cols-4 gap-3">
                        {[
                            { label: 'Media', value: `${avg}%`, color: avg >= 70 ? 'text-emerald-600 dark:text-emerald-400' : avg >= 50 ? 'text-amber-500' : 'text-red-500' },
                            { label: 'Mejor nota', value: `${best}%`, color: 'text-emerald-600 dark:text-emerald-400' },
                            { label: 'Peor nota', value: `${worst}%`, color: 'text-red-500' },
                            { label: 'Aprobados', value: `${filtered.length > 0 ? Math.round((passed / filtered.length) * 100) : 0}%`, color: 'text-indigo-600 dark:text-indigo-400' },
                        ].map(k => (
                            <div key={k.label} className="bg-gray-50 dark:bg-gray-800 rounded-xl p-3 text-center">
                                <div className={`text-xl font-bold ${k.color}`}>{k.value}</div>
                                <div className="text-xs text-gray-400 dark:text-gray-500 mt-0.5">{k.label}</div>
                            </div>
                        ))}
                    </div>

                    {/* SVG line chart */}
                    {filtered.length > 1 ? (
                        <div className="relative bg-gray-50 dark:bg-gray-800 rounded-2xl p-4 overflow-hidden">
                            {/* Grid lines */}
                            <div className="absolute inset-x-4 inset-y-4 flex flex-col justify-between pointer-events-none">
                                {[100, 75, 50, 25, 0].map(v => (
                                    <div key={v} className="flex items-center gap-2">
                                        <span className="text-[10px] text-gray-300 dark:text-gray-600 w-5 text-right shrink-0">{v}</span>
                                        <div className="flex-1 border-t border-gray-200 dark:border-gray-700 border-dashed" />
                                    </div>
                                ))}
                            </div>

                            <div className="ml-7 relative" style={{ height: 140 }}>
                                <svg width="100%" height="100%" viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none">
                                    <defs>
                                        <linearGradient id="overlayAreaGrad" x1="0" y1="0" x2="0" y2="1">
                                            <stop offset="0%" stopColor={lineColor} stopOpacity="0.25" />
                                            <stop offset="100%" stopColor={lineColor} stopOpacity="0.02" />
                                        </linearGradient>
                                    </defs>
                                    {areaD && <path d={areaD} fill="url(#overlayAreaGrad)" />}
                                    <path d={pathD} fill="none" stroke={lineColor} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                                    {points.map((p, i) => (
                                        <circle
                                            key={i}
                                            cx={p.x} cy={p.y} r={hoveredIdx === i ? 5 : 3}
                                            fill={lineColor}
                                            stroke="white" strokeWidth="1.5"
                                            className="cursor-pointer transition-all"
                                            onMouseEnter={() => setHoveredIdx(i)}
                                            onMouseLeave={() => setHoveredIdx(null)}
                                        />
                                    ))}
                                </svg>

                                {/* Tooltip */}
                                {hoveredIdx !== null && filtered[hoveredIdx] && (
                                    <div
                                        className="absolute z-10 pointer-events-none px-3 py-2 bg-gray-900/90 dark:bg-gray-100/90 rounded-xl shadow-xl text-xs"
                                        style={{
                                            left: `${(points[hoveredIdx].x / W) * 100}%`,
                                            top: `${(points[hoveredIdx].y / H) * 100}%`,
                                            transform: 'translate(-50%, -130%)',
                                        }}
                                    >
                                        <div className="font-bold text-white dark:text-gray-900" style={{ color: lineColor }}>{filtered[hoveredIdx].score}%</div>
                                        <div className="text-gray-300 dark:text-gray-600 max-w-[120px] truncate">{filtered[hoveredIdx].quizTitle}</div>
                                        <div className="text-gray-400 dark:text-gray-500">{filtered[hoveredIdx].date.toLocaleDateString()}</div>
                                    </div>
                                )}
                            </div>
                        </div>
                    ) : (
                        <div className="bg-gray-50 dark:bg-gray-800 rounded-2xl p-8 text-center text-sm text-gray-400">
                            {filtered.length === 0 ? 'Sin datos en este período' : 'Necesitas al menos 2 tests para ver la evolución'}
                        </div>
                    )}

                    {/* Bar chart for individual results */}
                    {filtered.length > 0 && (
                        <div>
                            <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 mb-2">Resultados individuales</p>
                            <div className="flex items-end gap-0.5 h-10 bg-gray-50 dark:bg-gray-800 rounded-xl px-3 py-2">
                                {filtered.map((d, i) => {
                                    const { bar } = getBarColor(d.score);
                                    return (
                                        <div
                                            key={i}
                                            className="flex-1 rounded-t-sm cursor-pointer transition-all duration-150 hover:opacity-100"
                                            style={{ height: `${d.score}%`, backgroundColor: bar, opacity: 0.8 }}
                                            title={`${d.score}% · ${d.quizTitle}`}
                                        />
                                    );
                                })}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

// ─── Mini Card (sidebar) ──────────────────────────────────────────────────────
const MiniStatsChart = ({ data = [], title = 'Evolución de notas', subtitle, role = 'student' }) => {
    const [showOverlay, setShowOverlay] = useState(false);
    const [hoveredIndex, setHoveredIndex] = useState(null);

    const scores = data.map(d => d.score);
    const overallAvg = scores.length > 0 ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length) : 0;

    const recentScores = scores.slice(-5);
    const avgRecent = recentScores.length > 0 ? recentScores.reduce((a, b) => a + b, 0) / recentScores.length : 0;
    const prevScores = scores.slice(-10, -5);
    const avgPrev = prevScores.length > 0 ? prevScores.reduce((a, b) => a + b, 0) / prevScores.length : avgRecent;
    const trend = avgRecent - avgPrev;

    const lineColor = overallAvg >= 70 ? '#22c55e' : overallAvg >= 50 ? '#f59e0b' : '#ef4444';
    const trendColor = trend > 2 ? 'text-emerald-500' : trend < -2 ? 'text-red-500' : 'text-gray-400';
    const TrendIcon = trend > 2 ? TrendingUp : trend < -2 ? TrendingDown : Minus;

    // Sparkline
    const W = 200; const H = 40;
    const points = scores.map((s, i) => ({
        x: scores.length > 1 ? (i / (scores.length - 1)) * W : W / 2,
        y: H - (s / 100) * H
    }));
    const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(' ');
    const areaD = points.length > 0
        ? `${pathD} L ${points[points.length - 1].x.toFixed(1)} ${H} L ${points[0].x.toFixed(1)} ${H} Z`
        : '';

    if (data.length === 0) {
        return (
            <div className="bg-white dark:bg-gray-800 p-5 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-sm transition-colors">
                <div className="flex items-center gap-2 mb-3">
                    <TrendingUp className="w-4 h-4 text-emerald-500" />
                    <h3 className="text-sm font-bold text-gray-800 dark:text-gray-100">{title}</h3>
                </div>
                <p className="text-xs text-gray-400 dark:text-gray-500 text-center py-6">Sin datos disponibles</p>
            </div>
        );
    }

    return (
        <>
            <button
                onClick={() => setShowOverlay(true)}
                className="w-full text-left bg-white dark:bg-gray-800 p-5 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-sm hover:shadow-md hover:border-emerald-300 dark:hover:border-emerald-700 transition-all group"
            >
                {/* Header */}
                <div className="flex items-center justify-between mb-1">
                    <div className="flex items-center gap-2">
                        <TrendingUp className="w-4 h-4 text-emerald-500" />
                        <h3 className="text-sm font-bold text-gray-800 dark:text-gray-100">{title}</h3>
                    </div>
                    <div className={`flex items-center gap-1 text-xs font-semibold ${trendColor}`}>
                        <TrendIcon className="w-3.5 h-3.5" />
                        <span>{trend > 0 ? '+' : ''}{Math.round(trend)}%</span>
                    </div>
                </div>
                {subtitle && <p className="text-xs text-gray-400 dark:text-gray-500 mb-3">{subtitle}</p>}

                {/* Sparkline */}
                <div className="my-3">
                    <svg width="100%" viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none" className="h-10">
                        <defs>
                            <linearGradient id="miniAreaGrad" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="0%" stopColor={lineColor} stopOpacity="0.3" />
                                <stop offset="100%" stopColor={lineColor} stopOpacity="0.02" />
                            </linearGradient>
                        </defs>
                        {areaD && <path d={areaD} fill="url(#miniAreaGrad)" />}
                        <path d={pathD} fill="none" stroke={lineColor} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                    </svg>
                </div>

                {/* Bar mini-chart */}
                <div className="flex items-end gap-0.5 h-8">
                    {scores.slice(-20).map((score, i) => {
                        const { bar } = getBarColor(score);
                        return (
                            <div
                                key={i}
                                className="flex-1 rounded-t-sm transition-all duration-150"
                                style={{ height: `${score}%`, backgroundColor: bar, opacity: 0.75 }}
                            />
                        );
                    })}
                </div>

                {/* Footer */}
                <div className="flex justify-between items-center mt-3 pt-3 border-t border-gray-100 dark:border-gray-700">
                    <span className="text-xs text-gray-400 dark:text-gray-500 group-hover:text-emerald-500 transition-colors">
                        Ver detalles →
                    </span>
                    <span className={`text-sm font-bold ${overallAvg >= 70 ? 'text-emerald-600 dark:text-emerald-400' : overallAvg >= 50 ? 'text-amber-500' : 'text-red-500'}`}>
                        {overallAvg}% media
                    </span>
                </div>
            </button>

            {showOverlay && (
                <ChartOverlay data={data} role={role} onClose={() => setShowOverlay(false)} />
            )}
        </>
    );
};

export default MiniStatsChart;

// src/pages/Profile/components/Notas.jsx
import React, { useState } from 'react';
import {
    ClipboardList, ChevronDown, ChevronUp, ArrowRight,
    TrendingUp, CheckCircle2, XCircle, BookOpen, Star
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';

/**
 * Notas — full-width panel
 *
 * Props:
 *   - subjectPerformance: [{ id, name, color, average, passRate, quizCount }]
 *   - recentActivity:     [{ id, quizTitle, subjectName, score, passed, date }]
 *   - role:               'student' | 'teacher'
 *   - teacherDashboardPath: string
 */

const gradeInfo = (score) => {
    if (score >= 90) return { label: 'Sobresaliente', color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/20', bar: '#22c55e' };
    if (score >= 70) return { label: 'Notable',        color: 'text-blue-600 dark:text-blue-400',       bg: 'bg-blue-50 dark:bg-blue-900/20',       bar: '#3b82f6' };
    if (score >= 60) return { label: 'Bien',           color: 'text-sky-600 dark:text-sky-400',         bg: 'bg-sky-50 dark:bg-sky-900/20',         bar: '#0ea5e9' };
    if (score >= 50) return { label: 'Aprobado',       color: 'text-amber-600 dark:text-amber-400',     bg: 'bg-amber-50 dark:bg-amber-900/20',     bar: '#f59e0b' };
    return             { label: 'Suspenso',            color: 'text-red-600 dark:text-red-400',         bg: 'bg-red-50 dark:bg-red-900/20',         bar: '#ef4444' };
};

const ScoreRing = ({ score, size = 48 }) => {
    const radius = (size - 6) / 2;
    const circ = 2 * Math.PI * radius;
    const { bar, color } = gradeInfo(score);
    return (
        <div className="relative flex items-center justify-center shrink-0" style={{ width: size, height: size }}>
            <svg width={size} height={size} style={{ transform: 'rotate(-90deg)' }}>
                <circle cx={size/2} cy={size/2} r={radius} fill="none" stroke="currentColor" strokeWidth="3" className="text-gray-100 dark:text-gray-700" />
                <circle cx={size/2} cy={size/2} r={radius} fill="none" stroke={bar} strokeWidth="3"
                    strokeDasharray={`${(score/100)*circ} ${circ}`} strokeLinecap="round" />
            </svg>
            <span className={`absolute text-xs font-bold ${color}`}>{score}</span>
        </div>
    );
};

const Notas = ({
    subjectPerformance = [],
    recentActivity = [],
    role = 'student',
    teacherDashboardPath = '/dashboard/stats',
}) => {
    const [showFinalGrades, setShowFinalGrades] = useState(false);
    const navigate = useNavigate ? useNavigate() : null;

    const overallAvg = subjectPerformance.length > 0
        ? Math.round(subjectPerformance.reduce((a, b) => a + b.average, 0) / subjectPerformance.length)
        : null;

    const overall = overallAvg !== null ? gradeInfo(overallAvg) : null;
    const passed  = recentActivity.filter(a => a.passed).length;
    const passRate = recentActivity.length > 0 ? Math.round((passed / recentActivity.length) * 100) : 0;

    return (
        <div className="bg-white dark:bg-gray-800 rounded-2xl border border-gray-200 dark:border-gray-700 shadow-sm transition-colors overflow-hidden">

            {/* ── Top summary row ─────────────────────────────────────────── */}
            <div className="flex flex-col sm:flex-row sm:items-center gap-4 px-6 py-5">
                {/* Icon + title */}
                <div className="flex items-center gap-3 flex-1 min-w-0">
                    <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-violet-500 flex items-center justify-center shadow-md shadow-indigo-400/30 shrink-0">
                        <ClipboardList className="w-5 h-5 text-white" />
                    </div>
                    <div>
