        const parsed = Number(trimmed);
        if (Number.isNaN(parsed)) return;

        const bounded = clamp(parsed, 0, 10);
        const payload = {
            subjectId: subject.id,
            quizId: quiz.id,
            userId: studentUid,
            overrideDecimal: bounded,
            reviewedBy: user?.uid || null,
            updatedAt: serverTimestamp()
        };

