            await updateDoc(doc(db, 'subjectAssignmentGradeReviews', existingDoc.id), payload);
            return;
        }

        await addDoc(collection(db, 'subjectAssignmentGradeReviews'), {
            ...payload,
            createdAt: serverTimestamp()
